INSERT INTO "public"."user_pages" ("id", "user_id", "title", "data", "thumbnail_url", "is_favorite", "is_public", "share_token", "last_accessed", "created_at", "updated_at") VALUES ('14c80993-6884-4f25-aaf7-b74320f56393', '3', 'Untitled Page', '{"theme":"theme-light-minimal","sections":[{"html":"<section id=\\"fp-theme-hero\\" class=\\"min-h-screen flex justify-center items-center relative has-bg-image section\\" data-section=\\"0\\" data-bg=\\"primary\\" data-original-bg=\\"gradient-themed-1\\" style=\\"background-color: var(--primary-bg);\\" data-fp-styles=\\"background-color: var(--primary-bg);\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"relative z-10 text-center px-4 w-full\\">\\n          <h1 class=\\"text-5xl md:text-7xl lg:text-8xl font-bold mb-8 animate-fade-in-up heading-themed in-viewport\\" style=\\"position: relative;\\">Welcome to the <span class=\\"block text-themed-accent\\"> Future </span></h1>\\n          <p class=\\"text-xl md:text-2xl lg:text-3xl mb-12 text-themed-secondary max-w-4xl mx-auto leading-relaxed in-viewport\\" style=\\"position: relative;\\">Experience innovation like never before with our cutting-edge solutions that transform the way you work</p>\\n          <div class=\\"flex flex-col sm:flex-row gap-6 justify-center items-center\\">\\n            <a href=\\"#\\" class=\\"btn-themed text-lg px-8 py-4 in-viewport\\" style=\\"position: relative;\\">Get Started</a>\\n            <a href=\\"#\\" class=\\"btn-themed-outline text-lg px-8 py-4 in-viewport\\" style=\\"position: relative;\\">Learn More</a>\\n          </div>\\n        </div>\\n        <div class=\\"absolute bottom-8 left-1/2 transform -translate-x-1/2 animate-bounce\\">\\n          <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down text-themed-accent w-8 h-8\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n        </div>\\n      </section>","number":"0"},{"html":"<section id=\\"fp-theme-discussion\\" class=\\"min-h-screen flex items-center section bg-features2-themed\\" data-section=\\"2\\" data-bg=\\"features2\\" data-original-bg=\\"gradient-themed-2\\" style=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-20 text-center\\">\\n          <h1 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-8 text-white in-viewport\\" style=\\"color: white !important; position: relative;\\"><span style=\\"color: #000000;\\">Seek discussion</span></h1>\\n          <p class=\\"text-lg md:text-xl mb-16 text-white text-opacity-90 max-w-4xl mx-auto leading-relaxed in-viewport\\" style=\\"position: relative;\\"><span style=\\"color: #000000;\\">There is something artificial when everyone is agreeing with each other. It''s useful to include people who don''t agree, and see their viewpoint or force yourself to explain things better.</span></p>\\n          <div class=\\"max-w-3xl mx-auto\\">\\n            <div class=\\"relative overflow-hidden rounded-2xl shadow-2xl\\">\\n              <img src=\\"https://images.unsplash.com/photo-1605810230434-7631ac76ec81?w=800&amp;h=500&amp;fit=crop\\" alt=\\"Group of people in discussion around video displays\\" class=\\"w-full h-auto object-cover in-viewport\\" style=\\"\\" loading=\\"lazy\\">\\n            </div>\\n          </div>\\n        </div>\\n      \\n        \\n    \\n        \\n    \\n        \\n    </section>","number":"2"},{"html":"<section id=\\"fp-theme-customer-testimonial\\" class=\\"min-h-screen flex items-center section bg-themed-secondary\\" data-section=\\"3\\" data-bg=\\"secondary\\" data-original-bg=\\"bg-themed-secondary\\" style=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-20\\">\\n          <div class=\\"text-center mb-16\\">\\n            <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold heading-themed mb-12\\" style=\\"position: relative;\\">What our customers say</h2>\\n          </div>\\n          <div class=\\"max-w-4xl mx-auto\\">\\n            <div class=\\"text-center mb-12\\">\\n              <p class=\\"text-xl md:text-2xl text-themed-primary leading-relaxed mb-8\\" style=\\"position: relative;\\">\\"You made it so simple. My new site is so much faster and easier to work with than my old site. I just choose the page, make the change and click save. No need to think twice before making it\\"</p>\\n            </div>\\n            <div class=\\"flex flex-col items-center\\">\\n              <div class=\\"mb-6\\">\\n                <h4 class=\\"text-xl font-bold heading-themed mb-2\\" style=\\"position: relative;\\">Jenny Wilson</h4>\\n                <p class=\\"text-themed-secondary\\" style=\\"position: relative;\\">Co-founder, Appson</p>\\n              </div>\\n              <div class=\\"flex space-x-4\\">\\n                <div class=\\"w-12 h-12 rounded-full overflow-hidden border-2 border-themed-accent\\">\\n                  <img src=\\"https://images.unsplash.com/photo-1438761681033-6461ffad8d80?ixlib=rb-4.0.3&amp;auto=format&amp;fit=crop&amp;w=60&amp;h=60&amp;q=80\\" alt=\\"Customer\\" class=\\"w-full h-full object-cover\\" style=\\"\\" loading=\\"lazy\\">\\n                </div>\\n                <div class=\\"w-12 h-12 rounded-full overflow-hidden border border-themed\\">\\n                  <img src=\\"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=60&amp;h=60&amp;fit=crop&amp;crop=face\\" alt=\\"Customer\\" class=\\"w-full h-full object-cover\\" style=\\"\\" loading=\\"lazy\\">\\n                </div>\\n                <div class=\\"w-12 h-12 rounded-full overflow-hidden border border-themed\\">\\n                  <img src=\\"https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=60&amp;h=60&amp;fit=crop&amp;crop=face\\" alt=\\"Customer\\" class=\\"w-full h-full object-cover\\" style=\\"\\" loading=\\"lazy\\">\\n                </div>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"3"},{"html":"<section id=\\"fp-theme-welcome\\" class=\\"items-center min-h-screen flex relative overflow-hidden section\\" style=\\"background: linear-gradient(rgba(0,0,0,0.6), rgba(0,0,0,0.6)), url(''https://images.unsplash.com/photo-1518770660439-4636190af475?w=2070&amp;h=1380&amp;fit=crop''); background-size: cover; background-position: center;\\" data-section=\\"47\\" data-original-bg=\\"\\" data-bg=\\"true\\" data-fp-styles=\\"background: linear-gradient(rgba(0,0,0,0.6), rgba(0,0,0,0.6)), url(''https://images.unsplash.com/photo-1518770660439-4636190af475?w=2070&amp;h=1380&amp;fit=crop''); background-size: cover; background-position: center;\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 text-center relative z-10\\">\\n          <h2 class=\\"text-4xl md:text-6xl lg:text-7xl font-bold mb-8 text-white\\" style=\\"font-family: var(--heading-font); position: relative;\\">Get UI Concept with 3D animation</h2>\\n          <p class=\\"text-xl md:text-2xl mb-12 text-white/90 max-w-4xl mx-auto\\" style=\\"position: relative;\\">Experience the future of design with our cutting-edge 3D animations and UI concepts that bring your vision to life.</p>\\n          <a href=\\"#\\" class=\\"inline-flex btn-themed text-lg px-8 py-4\\" style=\\"position: relative;\\">for $1990</a>\\n        </div>\\n      </section>","number":"47"},{"html":"<section id=\\"fp-theme-video-top\\" class=\\"relative min-h-screen w-full overflow-hidden flex items-start justify-center section has-bg-image\\" data-section=\\"58\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\" data-cloudinary-public-id=\\"fp-studio-media/atrigol@gmail.com/xhrc3w0owdxxgihtbp5y\\" data-cloudinary-format=\\"jpg\\" data-cloudinary-width=\\"465\\" data-cloudinary-height=\\"310\\">\\n          \\n        <video class=\\"absolute inset-0 w-full h-full object-cover\\" loop=\\"\\" muted=\\"\\" playsinline=\\"\\" autoplay=\\"\\" data-autoplay=\\"\\" data-keepplaying=\\"\\" allow=\\"autoplay\\" onloadedmetadata=\\"this.muted = true\\"><source src=\\"https://fp-assets.alvarotrigo.com/videos/forest.mp4\\" type=\\"video/mp4\\"><source src=\\"https://fp-assets.alvarotrigo.com/videos/forest.webm\\" type=\\"video/webm\\"></video></div>\\n        <div class=\\"absolute inset-0 bg-black/40\\"></div>\\n        <div class=\\"relative z-10 text-center mt-16 px-4\\">\\n          <h2 class=\\"text-4xl md:text-6xl lg:text-7xl font-bold text-white\\" style=\\"font-family: var(--heading-font); position: relative;\\">Innovation Drives Us</h2>\\n          <p class=\\"text-xl md:text-2xl text-white/90 mt-4 max-w-2xl mx-auto\\" style=\\"position: relative;\\">Advanced technology meets sustainable solutions</p>\\n        </div>\\n      \\n        \\n    \\n        \\n    </section>","number":"58"},{"html":"<section id=\\"fp-theme-pricing\\" class=\\"min-h-screen flex items-center bg-themed-secondary has-bg-image section\\" data-section=\\"27\\" data-bg=\\"secondary\\" data-original-bg=\\"bg-themed-secondary\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20\\">\\n          <div class=\\"text-center mb-20\\">\\n            <h2 class=\\"text-4xl md:text-6xl lg:text-7xl font-bold heading-themed mb-8\\" style=\\"position: relative;\\">Pricing</h2>\\n            <p class=\\"text-xl md:text-2xl text-themed-secondary max-w-4xl mx-auto leading-relaxed\\" style=\\"position: relative;\\">Choose the perfect plan that scales with your ambitions and drives your success</p>\\n          </div>\\n          <div class=\\"flex flex-wrap xl:flex-nowrap justify-center gap-10\\">\\n            <!-- Starter Plan -->\\n            <div data-fp-dynamic=\\"\\" class=\\"relative card-themed flex-shrink-0 basis-full md:basis-1/2 xl:basis-1/3 max-w-sm\\">\\n              <div class=\\"text-center\\">\\n                <h3 class=\\"text-3xl font-bold heading-themed mb-6\\" style=\\"position: relative;\\">Starter</h3>\\n                <div class=\\"text-5xl font-bold text-themed-primary mb-8\\">\\n                  <span style=\\"position: relative;\\">$29</span><span class=\\"text-xl text-themed-secondary\\" style=\\"position: relative;\\">/month</span>\\n                </div>\\n                <ul class=\\"space-y-4 mb-10\\">\\n                  <li class=\\"flex items-center text-themed-secondary text-lg\\" style=\\"position: relative;\\"><svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"check\\" class=\\"lucide lucide-check text-green-500 mr-4 w-5 h-5\\"><path d=\\"M20 6 9 17l-5-5\\"></path></svg>\\n<p>Basic Features</p></li>\\n                  <li class=\\"flex items-center text-themed-secondary text-lg\\" style=\\"position: relative;\\"><svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"check\\" class=\\"lucide lucide-check text-green-500 mr-4 w-5 h-5\\"><path d=\\"M20 6 9 17l-5-5\\"></path></svg>\\n<p>5 Projects</p></li>\\n                  <li class=\\"flex items-center text-themed-secondary text-lg\\" style=\\"position: relative;\\"><svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"check\\" class=\\"lucide lucide-check text-green-500 mr-4 w-5 h-5\\"><path d=\\"M20 6 9 17l-5-5\\"></path></svg>\\n<p>Email Support</p></li>\\n                </ul>\\n                <a href=\\"#\\" class=\\"flex justify-center btn-themed w-full text-lg py-4\\" style=\\"position: relative;\\">Choose Plan</a>\\n              </div>\\n            </div>\\n\\n            <!-- Pro Plan -->\\n            \\n\\n            <!-- Enterprise Plan -->\\n            <div data-fp-dynamic=\\"\\" class=\\"relative card-themed flex-shrink-0 basis-full md:basis-1/2 xl:basis-1/3 max-w-sm\\">\\n              <div class=\\"text-center\\">\\n                <h3 class=\\"text-3xl font-bold heading-themed mb-6\\" style=\\"position: relative;\\">Enterprise</h3>\\n                <div class=\\"text-5xl font-bold text-themed-primary mb-8\\">\\n                  <span style=\\"position: relative;\\">$199</span><span class=\\"text-xl text-themed-secondary\\" style=\\"position: relative;\\">/month</span>\\n                </div>\\n                <ul class=\\"space-y-4 mb-10\\">\\n                  <li class=\\"flex items-center text-themed-secondary text-lg\\" style=\\"position: relative;\\"><svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"check\\" class=\\"lucide lucide-check text-green-500 mr-4 w-5 h-5\\"><path d=\\"M20 6 9 17l-5-5\\"></path></svg>\\n<p>Custom Solutions</p></li>\\n                  <li class=\\"flex items-center text-themed-secondary text-lg\\" style=\\"position: relative;\\"><svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"check\\" class=\\"lucide lucide-check text-green-500 mr-4 w-5 h-5\\"><path d=\\"M20 6 9 17l-5-5\\"></path></svg>\\n<p>Dedicated Manager</p></li>\\n                  <li class=\\"flex items-center text-themed-secondary text-lg\\" style=\\"position: relative;\\"><svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"check\\" class=\\"lucide lucide-check text-green-500 mr-4 w-5 h-5\\"><path d=\\"M20 6 9 17l-5-5\\"></path></svg>\\n<p>SLA Guarantee</p></li>\\n                  <li class=\\"flex items-center text-themed-secondary text-lg\\" style=\\"position: relative;\\"><svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"check\\" class=\\"lucide lucide-check text-green-500 mr-4 w-5 h-5\\"><path d=\\"M20 6 9 17l-5-5\\"></path></svg>\\n<p>White-label Options</p></li>\\n                </ul>\\n                <a href=\\"#\\" class=\\"flex justify-center btn-themed w-full text-lg py-4\\" style=\\"position: relative;\\">Choose Plan</a>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"27"},{"html":"<section id=\\"fp-theme-faqs\\" class=\\"min-h-screen flex items-center bg-themed-secondary has-bg-image section\\" data-acc=\\"\\" data-acc-auto-open=\\"true\\" data-section=\\"36\\" data-bg=\\"secondary\\" data-original-bg=\\"bg-themed-secondary\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-20\\">\\n          <div class=\\"text-center mb-20\\">\\n            <h2 class=\\"text-4xl md:text-6xl lg:text-7xl font-bold heading-themed mb-8\\" style=\\"position: relative;\\">Frequently Asked Questions</h2>\\n            <p class=\\"text-xl md:text-2xl text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Everything you need to know about our platform and services</p>\\n          </div>\\n          <div class=\\"space-y-6\\">\\n            <div class=\\"card-themed\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full text-left flex justify-between items-center p-6 cursor-pointer\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold heading-themed\\" style=\\"position: relative;\\">How does the platform work?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 text-themed-accent transition-transform duration-300\\" data-acc-icon=\\"rotate\\" style=\\"transform: rotate(180deg);\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 102px;\\">\\n                <div class=\\"px-6 pb-6\\">\\n                  <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Our platform integrates seamlessly with your existing workflow. Simply sign up, connect your tools, and start collaborating with your team in real-time. The intuitive interface guides you through setup in just a few minutes.</p>\\n                </div>\\n              </div>\\n            </div>\\n            <div class=\\"card-themed\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full text-left flex justify-between items-center p-6 cursor-pointer\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold heading-themed\\" style=\\"position: relative;\\">What integrations are available?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 text-themed-accent transition-transform duration-300\\" data-acc-icon=\\"rotate\\" style=\\"transform: rotate(0deg);\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                <div class=\\"px-6 pb-6\\">\\n                  <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">We support over 50+ integrations including GitHub, Slack, Jira, Figma, and all major development tools. Our API also allows custom integrations for enterprise clients.</p>\\n                </div>\\n              </div>\\n            </div>\\n            <div class=\\"card-themed\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full text-left flex justify-between items-center p-6 cursor-pointer\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold heading-themed\\" style=\\"position: relative;\\">Is there a free trial?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 text-themed-accent transition-transform duration-300\\" data-acc-icon=\\"rotate\\" style=\\"transform: rotate(0deg);\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                <div class=\\"px-6 pb-6\\">\\n                  <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Yes! We offer a 14-day free trial with full access to all features. No credit card required to start your trial.</p>\\n                </div>\\n              </div>\\n            </div>\\n            <div class=\\"card-themed\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full text-left flex justify-between items-center p-6 cursor-pointer\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold heading-themed\\" style=\\"position: relative;\\">How secure is my data?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 text-themed-accent transition-transform duration-300\\" data-acc-icon=\\"rotate\\" style=\\"transform: rotate(0deg);\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                <div class=\\"px-6 pb-6\\">\\n                  <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">We use enterprise-grade security with end-to-end encryption, SOC 2 compliance, and regular security audits. Your data is stored in secure, redundant data centers with 99.9% uptime guarantee.</p>\\n                </div>\\n              </div>\\n            </div>\\n            <div class=\\"card-themed\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full text-left flex justify-between items-center p-6 cursor-pointer\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold heading-themed\\" style=\\"position: relative;\\">Can I cancel anytime?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 text-themed-accent transition-transform duration-300\\" data-acc-icon=\\"rotate\\" style=\\"transform: rotate(0deg);\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                <div class=\\"px-6 pb-6\\">\\n                  <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Absolutely. You can cancel your subscription at any time with no cancellation fees. You''ll continue to have access until the end of your billing period.</p>\\n                </div>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"36"},{"html":"<section id=\\"fp-theme-popular-questions\\" class=\\"min-h-screen flex items-center has-bg-image section\\" style=\\"background: var(--primary-bg);\\" data-acc=\\"\\" data-acc-auto-open=\\"false\\" data-section=\\"107\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20\\">\\n          <!-- Header -->\\n          <div class=\\"text-center mb-16\\">\\n            <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-6\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">Popular Questions</h2>\\n            <p class=\\"text-lg md:text-xl max-w-4xl mx-auto leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">This section highlights the inquiries that are most relevant to the audience, providing clear and concise answers to help address the most common concerns or interests.</p>\\n          </div>\\n\\n          <!-- Content Grid -->\\n          <div class=\\"grid lg:grid-cols-3 gap-8 max-w-6xl mx-auto\\">\\n            <!-- Left Sidebar - Categories -->\\n            <div class=\\"lg:col-span-1 space-y-4 flex flex-col\\">\\n              <!-- General Category -->\\n              <button data-faq-category=\\"general\\" class=\\"fp-keep-color w-full text-left p-6 rounded-2xl transition-all flex-1 active-category\\" style=\\"background: var(--primary-accent); border-radius: var(--card-radius); box-shadow: var(--shadow-md); border: none; position: relative;\\"><svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"home\\" class=\\"lucide lucide-home w-6 h-6 flex-shrink-0\\" style=\\"color: var(--secondary-text);\\"><path d=\\"M15 21v-8a1 1 0 0 0-1-1h-4a1 1 0 0 0-1 1v8\\"></path><path d=\\"M3 10a2 2 0 0 1 .709-1.528l7-6a2 2 0 0 1 2.582 0l7 6A2 2 0 0 1 21 10v9a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z\\"></path></svg>GeneralWelcome to the General section, where you can find essential information and resources to help you navigate our services.</button>\\n\\n              <!-- Support Category -->\\n              <button data-faq-category=\\"support\\" class=\\"fp-keep-color w-full text-left p-6 rounded-2xl transition-all flex-1 active-category\\" style=\\"background: var(--primary-accent); border-radius: var(--card-radius); box-shadow: var(--shadow-md); border: none; position: relative;\\"><svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"message-circle\\" class=\\"lucide lucide-message-circle w-6 h-6 flex-shrink-0\\" style=\\"color: var(--secondary-text);\\"><path d=\\"M2.992 16.342a2 2 0 0 1 .094 1.167l-1.065 3.29a1 1 0 0 0 1.236 1.168l3.413-.998a2 2 0 0 1 1.099.092 10 10 0 1 0-4.777-4.719\\"></path></svg>SupportOur dedicated support team is here to assist you with any questions or issues you may have. We provide prompt, professional assistance.</button>\\n\\n              <!-- Other Category -->\\n              <button data-faq-category=\\"other\\" class=\\"fp-keep-color w-full text-left p-6 rounded-2xl transition-all flex-1 active-category\\" style=\\"background: var(--primary-accent); border-radius: var(--card-radius); box-shadow: var(--shadow-md); border: none; position: relative;\\"><svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"grid-2x2\\" class=\\"lucide lucide-grid-2x2 w-6 h-6 flex-shrink-0\\" style=\\"color: var(--secondary-text);\\"><path d=\\"M12 3v18\\"></path><path d=\\"M3 12h18\\"></path><rect x=\\"3\\" y=\\"3\\" width=\\"18\\" height=\\"18\\" rx=\\"2\\"></rect></svg>OtherIf you have specific needs or inquiries that don''t fall into our standard categories, we''re here to help.</button>\\n            </div>\\n\\n            <!-- Right Side - FAQ Accordion -->\\n            <div class=\\"lg:col-span-2\\">\\n              <h3 id=\\"faq-category-title\\" class=\\"text-3xl md:text-4xl font-bold mb-8\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">Other Questions</h3>\\n              \\n              <!-- FAQ Items Container (populated by JS) -->\\n              <div id=\\"faq-accordion-container\\" class=\\"fp-keep-color\\"><div class=\\"faq-item p-6 rounded-2xl mb-4 cursor-pointer\\" data-acc-item=\\"\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\">\\n        <div class=\\"w-full flex justify-between items-start\\">\\n          <h3 class=\\"text-lg font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">Do you offer refunds?</h3>\\n          <i data-lucide=\\"chevron-down\\" class=\\"w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text);\\" data-acc-icon=\\"rotate\\"></i>\\n        </div>\\n        <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n          <div class=\\"mt-4\\">\\n            <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">If you have specific needs or inquiries that don''t fall into our standard categories, we''re here to help. Yes, we offer a 30-day money-back guarantee on all our products and services. If you''re not satisfied, contact our support team to initiate a refund request.</p>\\n          </div>\\n        </div>\\n      </div><div class=\\"faq-item p-6 rounded-2xl mb-4 cursor-pointer\\" data-acc-item=\\"\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\">\\n        <div class=\\"w-full flex justify-between items-start\\">\\n          <h3 class=\\"text-lg font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">Can I upgrade or downgrade my plan?</h3>\\n          <i data-lucide=\\"chevron-down\\" class=\\"w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text);\\" data-acc-icon=\\"rotate\\"></i>\\n        </div>\\n        <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n          <div class=\\"mt-4\\">\\n            <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">Absolutely! You can change your subscription plan at any time from your account dashboard. Upgrades take effect immediately, while downgrades will be applied at the start of your next billing cycle.</p>\\n          </div>\\n        </div>\\n      </div><div class=\\"faq-item p-6 rounded-2xl mb-4 cursor-pointer\\" data-acc-item=\\"\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\">\\n        <div class=\\"w-full flex justify-between items-start\\">\\n          <h3 class=\\"text-lg font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">Is my data secure?</h3>\\n          <i data-lucide=\\"chevron-down\\" class=\\"w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text);\\" data-acc-icon=\\"rotate\\"></i>\\n        </div>\\n        <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n          <div class=\\"mt-4\\">\\n            <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">We take data security very seriously. All your information is encrypted using industry-standard SSL/TLS protocols. We comply with GDPR, CCPA, and other data protection regulations to ensure your privacy is protected.</p>\\n          </div>\\n        </div>\\n      </div></div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"107"},{"html":"<section id=\\"fp-theme-inline-faq\\" class=\\"min-h-screen items-center has-bg-image section\\" style=\\"background: var(--primary-bg);\\" data-section=\\"108\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 py-24\\">\\n          <!-- Header -->\\n          <div class=\\"text-center mb-16\\">\\n            <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-6\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">FAQ</h2>\\n            <p class=\\"text-lg md:text-xl max-w-4xl mx-auto leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">The FAQ section provides answers to common questions about our products, services, policies, and procedures. It''s designed to help you find quick solutions and information</p>\\n          </div>\\n          \\n          <!-- FAQ Grid -->\\n          <div class=\\"fp-keep-color grid md:grid-cols-2 gap-8\\">\\n            <!-- FAQ Item 1 -->\\n            <div class=\\"p-6 rounded-2xl\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\">\\n              <div class=\\"mb-4\\">\\n                <h3 class=\\"text-xl font-bold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\"><span style=\\"color: var(--primary-accent);\\">Q.</span> How can I contact customer support?</h3>\\n              </div>\\n              <div>\\n                <p class=\\"text-sm leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\"><span style=\\"color: var(--primary-accent); font-weight: 600;\\">A.</span> You can reach us through email, live chat, or phone support available 24/7.</p>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 2 -->\\n            <div class=\\"p-6 rounded-2xl\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\">\\n              <div class=\\"mb-4\\">\\n                <h3 class=\\"text-xl font-bold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\"><span style=\\"color: var(--primary-accent);\\">Q.</span> How do I delete my account?</h3>\\n              </div>\\n              <div>\\n                <p class=\\"text-sm leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\"><span style=\\"color: var(--primary-accent); font-weight: 600;\\">A.</span> Visit your account settings and select the account deletion option.</p>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 3 -->\\n            <div class=\\"p-6 rounded-2xl\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\">\\n              <div class=\\"mb-4\\">\\n                <h3 class=\\"text-xl font-bold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\"><span style=\\"color: var(--primary-accent);\\">Q.</span> How can I reset my password?</h3>\\n              </div>\\n              <div>\\n                <p class=\\"text-sm leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\"><span style=\\"color: var(--primary-accent); font-weight: 600;\\">A.</span> Click \\"Forgot Password\\" on the login page and follow the email instructions.</p>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 4 -->\\n            <div class=\\"p-6 rounded-2xl\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\">\\n              <div class=\\"mb-4\\">\\n                <h3 class=\\"text-xl font-bold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\"><span style=\\"color: var(--primary-accent);\\">Q.</span> How do I update my profile information?</h3>\\n              </div>\\n              <div>\\n                <p class=\\"text-sm leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\"><span style=\\"color: var(--primary-accent); font-weight: 600;\\">A.</span> Navigate to account settings, select \\"Profile\\", and update your information.</p>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 5 -->\\n            <div class=\\"p-6 rounded-2xl\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\">\\n              <div class=\\"mb-4\\">\\n                <h3 class=\\"text-xl font-bold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\"><span style=\\"color: var(--primary-accent);\\">Q.</span> Which is better short term or long term?</h3>\\n              </div>\\n              <div>\\n                <p class=\\"text-sm leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\"><span style=\\"color: var(--primary-accent); font-weight: 600;\\">A.</span> The choice depends on your goals, risk tolerance, and financial situation.</p>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 6 -->\\n            <div class=\\"p-6 rounded-2xl\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\">\\n              <div class=\\"mb-4\\">\\n                <h3 class=\\"text-xl font-bold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\"><span style=\\"color: var(--primary-accent);\\">Q.</span> How do I change my email address?</h3>\\n              </div>\\n              <div>\\n                <p class=\\"text-sm leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\"><span style=\\"color: var(--primary-accent); font-weight: 600;\\">A.</span> Contact customer support via the \\"Help\\" button or email for assistance.</p>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"108"},{"html":"<section id=\\"fp-theme-faq-visible\\" class=\\"min-h-screen flex items-center has-bg-image section\\" style=\\"background: var(--primary-bg);\\" data-section=\\"111\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 py-24\\">\\n          <div class=\\"grid lg:grid-cols-2 gap-16 items-start\\">\\n            <!-- Left Side - FAQs -->\\n            <div>\\n              <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-12\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">Frequently Asked Question</h2>\\n\\n              <!-- FAQ List -->\\n              <div class=\\"space-y-8 mb-12\\">\\n                <!-- FAQ Item 1 -->\\n                <div class=\\"flex gap-6\\">\\n                  <!-- Circular Bullet with Question Mark -->\\n                  <div class=\\"flex-shrink-0 w-12 h-12 rounded-full flex items-center justify-center\\" style=\\"background: var(--primary-accent);\\">\\n                    <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"help-circle\\" class=\\"lucide lucide-help-circle w-6 h-6 text-white\\"><circle cx=\\"12\\" cy=\\"12\\" r=\\"10\\"></circle><path d=\\"M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3\\"></path><path d=\\"M12 17h.01\\"></path></svg>\\n                  </div>\\n                  <div class=\\"flex-1\\">\\n                    <h3 class=\\"text-xl font-semibold mb-3\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How can I contact customer support?</h3>\\n                    <p class=\\"text-sm leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">To contact customer support, look for a \\"Contact us\\" or \\"Help\\" button or link on the website or platform. You may be able to email, call, or chat with customer support for assistance.</p>\\n                  </div>\\n                </div>\\n\\n                <!-- FAQ Item 2 -->\\n                <div class=\\"flex gap-6\\">\\n                  <!-- Circular Bullet with Question Mark -->\\n                  <div class=\\"flex-shrink-0 w-12 h-12 rounded-full flex items-center justify-center\\" style=\\"background: var(--primary-accent);\\">\\n                    <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"help-circle\\" class=\\"lucide lucide-help-circle w-6 h-6 text-white\\"><circle cx=\\"12\\" cy=\\"12\\" r=\\"10\\"></circle><path d=\\"M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3\\"></path><path d=\\"M12 17h.01\\"></path></svg>\\n                  </div>\\n                  <div class=\\"flex-1\\">\\n                    <h3 class=\\"text-xl font-semibold mb-3\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How can I reset my password?</h3>\\n                    <p class=\\"text-sm leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">Go to the login page and click on the \\"Forgot password\\" link. Enter the email associated with your account, and you will receive an email with instructions on how to reset your password.</p>\\n                  </div>\\n                </div>\\n\\n                <!-- FAQ Item 3 -->\\n                <div class=\\"flex gap-6\\">\\n                  <!-- Circular Bullet with Question Mark -->\\n                  <div class=\\"flex-shrink-0 w-12 h-12 rounded-full flex items-center justify-center\\" style=\\"background: var(--primary-accent);\\">\\n                    <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"help-circle\\" class=\\"lucide lucide-help-circle w-6 h-6 text-white\\"><circle cx=\\"12\\" cy=\\"12\\" r=\\"10\\"></circle><path d=\\"M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3\\"></path><path d=\\"M12 17h.01\\"></path></svg>\\n                  </div>\\n                  <div class=\\"flex-1\\">\\n                    <h3 class=\\"text-xl font-semibold mb-3\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How do I change my privacy settings?</h3>\\n                    <p class=\\"text-sm leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">To change your privacy settings, log in and go to the settings or account page. Look for an option to \\"Privacy\\" or \\"Security\\" and follow the instructions.</p>\\n                  </div>\\n                </div>\\n              </div>\\n\\n              <!-- View All FAQs Button -->\\n              <button class=\\"btn-themed px-8 py-4 rounded-full text-lg font-semibold transition-all duration-300 hover:scale-105 shadow-lg\\" style=\\"position: relative;\\">View All FAQs</button>\\n            </div>\\n\\n            <!-- Right Side - Image -->\\n            <div class=\\"relative lg:sticky lg:top-24\\">\\n              <div class=\\"rounded-3xl overflow-hidden shadow-2xl\\" style=\\"box-shadow: var(--shadow-lg);\\">\\n                <img src=\\"./public/images/business-team.jpg\\" alt=\\"Customer support representative\\" class=\\"w-full h-auto object-cover\\" style=\\"border-radius: var(--card-radius);\\" loading=\\"lazy\\">\\n              </div>\\n              <!-- Decorative element -->\\n              <div class=\\"absolute -top-6 -left-6 w-32 h-32 rounded-full opacity-20 blur-3xl\\" style=\\"background: var(--primary-accent);\\"></div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"111"},{"html":"<section id=\\"fp-theme-questions-answers\\" class=\\"min-h-screen items-center has-bg-image section\\" style=\\"background: var(--primary-bg);\\" data-acc=\\"\\" data-acc-auto-open=\\"false\\" data-section=\\"106\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 py-24\\">\\n          <div class=\\"text-center mb-16\\">\\n            <p class=\\"text-sm font-semibold uppercase tracking-wider mb-4\\" style=\\"color: var(--secondary-text); position: relative;\\">FAQs</p>\\n            <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">Questions &amp; Answers</h2>\\n          </div>\\n          \\n          <div class=\\"grid md:grid-cols-2 gap-8 items-start fp-keep-color\\">\\n            <!-- FAQ Item 1 -->\\n            <div class=\\"p-6 rounded-2xl cursor-pointer\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full flex justify-between items-start\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How can I contact customer support?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                <div class=\\"mt-4\\">\\n                  <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">To contact customer support, look for a \\"Contact us\\" or \\"Help\\" button or link on the website or platform. You may be able to email, call, or chat with customer support for assistance with your questions or concerns.</p>\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 2 -->\\n            <div class=\\"p-6 rounded-2xl cursor-pointer\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full flex justify-between items-start\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How do I join a group or community?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0px;\\">\\n                <div class=\\"mt-4\\">\\n                  <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">It may also provide information on how to find the right group or community that aligns with your interests or goals, and offer tips for getting started and engaging effectively within the group.</p>\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 3 -->\\n            <div class=\\"p-6 rounded-2xl cursor-pointer\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full flex justify-between items-start\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How can I reset my password?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                <div class=\\"mt-4\\">\\n                  <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">To reset your password, click on the \\"Forgot Password\\" link on the login page. Enter your email address and follow the instructions sent to your inbox to create a new secure password for your account.</p>\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 4 -->\\n            <div class=\\"p-6 rounded-2xl cursor-pointer\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full flex justify-between items-start\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How do I delete my account?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0px;\\">\\n                <div class=\\"mt-4\\">\\n                  <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">To delete your account, go to your account settings and look for the \\"Delete Account\\" option. Please note that this action is permanent and will remove all your data from our system. Make sure to back up any important information before proceeding.</p>\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 5 -->\\n            <div class=\\"p-6 rounded-2xl cursor-pointer\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full flex justify-between items-start\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">What payment methods do you accept?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                <div class=\\"mt-4\\">\\n                  <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">We accept all major credit cards including Visa, Mastercard, American Express, and Discover. We also support PayPal and digital wallets like Apple Pay and Google Pay for your convenience and security.</p>\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 6 -->\\n            <div class=\\"p-6 rounded-2xl cursor-pointer\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full flex justify-between items-start\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How can I change my password?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                <div class=\\"mt-4\\">\\n                  <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">Navigate to your account settings, select \\"Security\\" or \\"Password\\" section, and click on \\"Change Password\\". Enter your current password followed by your new password twice to confirm the change. Make sure to use a strong, unique password.</p>\\n                </div>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"106"},{"html":"<section id=\\"fp-theme-faq-image\\" class=\\"min-h-screen flex items-center has-bg-image section\\" style=\\"background: var(--primary-bg);\\" data-acc=\\"\\" data-acc-auto-open=\\"false\\" data-section=\\"110\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 py-24\\">\\n          <div class=\\"grid lg:grid-cols-2 gap-16 items-center\\">\\n            <!-- Left Side - FAQs -->\\n            <div>\\n              <p class=\\"text-sm font-semibold uppercase tracking-wider mb-4\\" style=\\"color: var(--secondary-text); position: relative;\\">Question &amp; Answer</p>\\n              <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-12\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">Most Asked Question</h2>\\n\\n              <!-- FAQ List -->\\n              <div class=\\"space-y-6\\">\\n                <!-- FAQ Item 1 -->\\n                <div class=\\"cursor-pointer border-b pb-6 transition-all duration-300\\" style=\\"border-color: var(--border-color);\\" data-acc-item=\\"\\">\\n                  <div class=\\"flex justify-between items-start gap-4\\" style=\\"cursor: pointer;\\">\\n                    <h3 class=\\"text-xl font-semibold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">fadsfafafafa</h3>\\n                    <div class=\\"w-6 h-6 flex-shrink-0 transition-all duration-300\\" data-acc-icon=\\"plus-minus\\">\\n                      <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"plus\\" data-icon-plus=\\"\\" style=\\"color: var(--primary-text);\\" class=\\"lucide lucide-plus\\"><path d=\\"M5 12h14\\"></path><path d=\\"M12 5v14\\"></path></svg>\\n                      <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"minus\\" data-icon-minus=\\"\\" class=\\"lucide lucide-minus hidden\\" style=\\"color: var(--primary-text);\\"><path d=\\"M5 12h14\\"></path></svg>\\n                    </div>\\n                  </div>\\n                  <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0px;\\">\\n                    <div class=\\"mt-4\\">\\n                      <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">fadsfasfasfasfa</p>\\n                    </div>\\n                  </div>\\n                </div>\\n\\n                <!-- FAQ Item 2 -->\\n                <div class=\\"cursor-pointer border-b pb-6 transition-all duration-300\\" style=\\"border-color: var(--border-color);\\" data-acc-item=\\"\\">\\n                  <div class=\\"flex justify-between items-start gap-4\\" style=\\"cursor: pointer;\\">\\n                    <h3 class=\\"text-xl font-semibold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How do I delete my account?</h3>\\n                    <div class=\\"w-6 h-6 flex-shrink-0 transition-all duration-300\\" data-acc-icon=\\"plus-minus\\">\\n                      <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"plus\\" data-icon-plus=\\"\\" style=\\"color: var(--primary-text);\\" class=\\"lucide lucide-plus hidden\\"><path d=\\"M5 12h14\\"></path><path d=\\"M12 5v14\\"></path></svg>\\n                      <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"minus\\" data-icon-minus=\\"\\" class=\\"lucide lucide-minus\\" style=\\"color: var(--primary-text);\\"><path d=\\"M5 12h14\\"></path></svg>\\n                    </div>\\n                  </div>\\n                  <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 94px;\\">\\n                    <div class=\\"mt-4\\">\\n                      <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">Visit your account settings and look for the \\"Delete Account\\" option. This action is permanent and will remove all your data. We recommend downloading any important information before proceeding with account deletion.</p>\\n                    </div>\\n                  </div>\\n                </div>\\n\\n                <!-- FAQ Item 3 -->\\n                <div class=\\"cursor-pointer border-b pb-6 transition-all duration-300\\" style=\\"border-color: var(--border-color);\\" data-acc-item=\\"\\">\\n                  <div class=\\"flex justify-between items-start gap-4\\" style=\\"cursor: pointer;\\">\\n                    <h3 class=\\"text-xl font-semibold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How do I join a group or community?</h3>\\n                    <div class=\\"w-6 h-6 flex-shrink-0 transition-all duration-300\\" data-acc-icon=\\"plus-minus\\">\\n                      <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"plus\\" data-icon-plus=\\"\\" style=\\"color: var(--primary-text);\\" class=\\"lucide lucide-plus\\"><path d=\\"M5 12h14\\"></path><path d=\\"M12 5v14\\"></path></svg>\\n                      <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"minus\\" data-icon-minus=\\"\\" class=\\"lucide lucide-minus hidden\\" style=\\"color: var(--primary-text);\\"><path d=\\"M5 12h14\\"></path></svg>\\n                    </div>\\n                  </div>\\n                  <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                    <div class=\\"mt-4\\">\\n                      <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">Navigate to the Communities section and browse available groups. Click \\"Join\\" on any community that interests you. Some groups may require approval from administrators before you can participate.</p>\\n                    </div>\\n                  </div>\\n                </div>\\n\\n                <!-- FAQ Item 4 -->\\n                <div class=\\"cursor-pointer border-b pb-6 transition-all duration-300\\" style=\\"border-color: var(--border-color);\\" data-acc-item=\\"\\">\\n                  <div class=\\"flex justify-between items-start gap-4\\" style=\\"cursor: pointer;\\">\\n                    <h3 class=\\"text-xl font-semibold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How can I contact customer support?</h3>\\n                    <div class=\\"w-6 h-6 flex-shrink-0 transition-all duration-300\\" data-acc-icon=\\"plus-minus\\">\\n                      <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"plus\\" data-icon-plus=\\"\\" style=\\"color: var(--primary-text);\\" class=\\"lucide lucide-plus\\"><path d=\\"M5 12h14\\"></path><path d=\\"M12 5v14\\"></path></svg>\\n                      <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"minus\\" data-icon-minus=\\"\\" class=\\"lucide lucide-minus hidden\\" style=\\"color: var(--primary-text);\\"><path d=\\"M5 12h14\\"></path></svg>\\n                    </div>\\n                  </div>\\n                  <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                    <div class=\\"mt-4\\">\\n                      <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">Our customer support team is available 24/7 via email, live chat, or phone. You can access support through the Help button in your dashboard or visit our support center at support.example.com.</p>\\n                    </div>\\n                  </div>\\n                </div>\\n\\n                <!-- FAQ Item 5 -->\\n                <div class=\\"cursor-pointer border-b pb-6 transition-all duration-300\\" style=\\"border-color: var(--border-color);\\" data-acc-item=\\"\\">\\n                  <div class=\\"flex justify-between items-start gap-4\\" style=\\"cursor: pointer;\\">\\n                    <h3 class=\\"text-xl font-semibold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">Which is better short term or long term?</h3>\\n                    <div class=\\"w-6 h-6 flex-shrink-0 transition-all duration-300\\" data-acc-icon=\\"plus-minus\\">\\n                      <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"plus\\" data-icon-plus=\\"\\" style=\\"color: var(--primary-text);\\" class=\\"lucide lucide-plus\\"><path d=\\"M5 12h14\\"></path><path d=\\"M12 5v14\\"></path></svg>\\n                      <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"minus\\" data-icon-minus=\\"\\" class=\\"lucide lucide-minus hidden\\" style=\\"color: var(--primary-text);\\"><path d=\\"M5 12h14\\"></path></svg>\\n                    </div>\\n                  </div>\\n                  <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                    <div class=\\"mt-4\\">\\n                      <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">The choice depends on your goals and financial situation. Short-term plans offer flexibility, while long-term plans often provide better value and stability. Contact our advisors for personalized recommendations.</p>\\n                    </div>\\n                  </div>\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- Right Side - Image -->\\n            <div class=\\"relative\\">\\n              <div class=\\"rounded-3xl overflow-hidden shadow-2xl\\" style=\\"box-shadow: var(--shadow-lg);\\">\\n                <img src=\\"./public/images/workspace.jpg\\" alt=\\"Workspace dashboard illustration\\" class=\\"w-full h-auto object-cover\\" style=\\"border-radius: var(--card-radius);\\" loading=\\"lazy\\">\\n              </div>\\n              <!-- Decorative element -->\\n              <div class=\\"absolute -bottom-6 -right-6 w-48 h-48 rounded-full opacity-20 blur-3xl\\" style=\\"background: var(--primary-accent);\\"></div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"110"},{"html":"<section id=\\"fp-theme-questions-answers\\" class=\\"min-h-screen items-center has-bg-image section\\" style=\\"background: var(--primary-bg);\\" data-acc=\\"\\" data-acc-auto-open=\\"false\\" data-section=\\"106\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 py-24\\">\\n          <div class=\\"text-center mb-16\\">\\n            <p class=\\"text-sm font-semibold uppercase tracking-wider mb-4\\" style=\\"color: var(--secondary-text); position: relative;\\">FAQs</p>\\n            <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">Questions &amp; Answers</h2>\\n          </div>\\n          \\n          <div class=\\"grid md:grid-cols-2 gap-8 items-start fp-keep-color\\">\\n            <!-- FAQ Item 1 -->\\n            <div class=\\"p-6 rounded-2xl cursor-pointer\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full flex justify-between items-start\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How can I contact customer support?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0px;\\">\\n                <div class=\\"mt-4\\">\\n                  <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">To contact customer support, look for a \\"Contact us\\" or \\"Help\\" button or link on the website or platform. You may be able to email, call, or chat with customer support for assistance with your questions or concerns.</p>\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 2 -->\\n            <div class=\\"p-6 rounded-2xl cursor-pointer\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full flex justify-between items-start\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How do I join a group or community?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0px;\\">\\n                <div class=\\"mt-4\\">\\n                  <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">It may also provide information on how to find the right group or community that aligns with your interests or goals, and offer tips for getting started and engaging effectively within the group.</p>\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 3 -->\\n            <div class=\\"p-6 rounded-2xl cursor-pointer\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full flex justify-between items-start\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How can I reset my password?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                <div class=\\"mt-4\\">\\n                  <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">To reset your password, click on the \\"Forgot Password\\" link on the login page. Enter your email address and follow the instructions sent to your inbox to create a new secure password for your account.</p>\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 4 -->\\n            <div class=\\"p-6 rounded-2xl cursor-pointer\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full flex justify-between items-start\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How do I delete my account?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                <div class=\\"mt-4\\">\\n                  <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">To delete your account, go to your account settings and look for the \\"Delete Account\\" option. Please note that this action is permanent and will remove all your data from our system. Make sure to back up any important information before proceeding.</p>\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 5 -->\\n            <div class=\\"p-6 rounded-2xl cursor-pointer\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full flex justify-between items-start\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">What payment methods do you accept?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                <div class=\\"mt-4\\">\\n                  <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">We accept all major credit cards including Visa, Mastercard, American Express, and Discover. We also support PayPal and digital wallets like Apple Pay and Google Pay for your convenience and security.</p>\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- FAQ Item 6 -->\\n            <div class=\\"p-6 rounded-2xl cursor-pointer\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius); box-shadow: var(--shadow-sm); border: 1px solid var(--border-color);\\" data-acc-item=\\"\\">\\n              <div class=\\"w-full flex justify-between items-start\\" style=\\"cursor: pointer;\\">\\n                <h3 class=\\"text-xl font-semibold pr-4\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How can I change my password?</h3>\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n              </div>\\n              <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                <div class=\\"mt-4\\">\\n                  <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">Navigate to your account settings, select \\"Security\\" or \\"Password\\" section, and click on \\"Change Password\\". Enter your current password followed by your new password twice to confirm the change. Make sure to use a strong, unique password.</p>\\n                </div>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"106"},{"html":"<section id=\\"fp-theme-split-faq\\" class=\\"min-h-screen flex items-center has-bg-image section\\" style=\\"background: var(--primary-bg);\\" data-acc=\\"\\" data-acc-auto-open=\\"false\\" data-section=\\"109\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 py-24\\">\\n          <div class=\\"grid lg:grid-cols-2 gap-16 items-start\\">\\n            <!-- Left Side - Heading & CTA -->\\n            <div class=\\"lg:sticky lg:top-24\\">\\n              <p class=\\"text-sm font-semibold uppercase tracking-wider mb-4\\" style=\\"color: var(--primary-accent); position: relative;\\">Most asked queries</p>\\n              <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-6\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">Frequently asked questions</h2>\\n              <p class=\\"text-lg md:text-xl mb-8 leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">Trusted by over 10,000 users worldwide. We''re here to answer your questions and provide the support you need.</p>\\n              <button class=\\"btn-themed px-8 py-4 rounded-full font-semibold text-lg transition-all duration-300 hover:scale-105\\" style=\\"position: relative;\\">Contact us</button>\\n            </div>\\n\\n            <!-- Right Side - FAQ List -->\\n            <div class=\\"space-y-4\\">\\n              <!-- FAQ Item 1 -->\\n              <div class=\\"cursor-pointer border-b transition-all duration-300\\" style=\\"border-color: var(--border-color); padding-bottom: 1.5rem;\\" data-acc-item=\\"\\">\\n                <div class=\\"flex justify-between items-start gap-4\\" style=\\"cursor: pointer;\\">\\n                  <h3 class=\\"text-xl font-semibold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How can I reset my password?</h3>\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n                </div>\\n                <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                  <div class=\\"mt-4\\" style=\\"padding-top: 0.5rem;\\">\\n                    <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">Click on \\"Forgot Password\\" on the login page and follow the instructions sent to your email. If you encounter any issues, our support team is available 24/7 to assist you.</p>\\n                  </div>\\n                </div>\\n              </div>\\n\\n              <!-- FAQ Item 2 -->\\n              <div class=\\"cursor-pointer border-b transition-all duration-300\\" style=\\"border-color: var(--border-color); padding-bottom: 1.5rem;\\" data-acc-item=\\"\\">\\n                <div class=\\"flex justify-between items-start gap-4\\" style=\\"cursor: pointer;\\">\\n                  <h3 class=\\"text-xl font-semibold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How do I update my profile information?</h3>\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n                </div>\\n                <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0px;\\">\\n                  <div class=\\"mt-4\\" style=\\"padding-top: 0.5rem;\\">\\n                    <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">Navigate to your account settings, select \\"Profile\\", and update your personal information including name, email, and preferences. Changes are saved automatically.</p>\\n                  </div>\\n                </div>\\n              </div>\\n\\n              <!-- FAQ Item 3 -->\\n              <div class=\\"cursor-pointer border-b transition-all duration-300\\" style=\\"border-color: var(--border-color); padding-bottom: 1.5rem;\\" data-acc-item=\\"\\">\\n                <div class=\\"flex justify-between items-start gap-4\\" style=\\"cursor: pointer;\\">\\n                  <h3 class=\\"text-xl font-semibold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How do I update my billing information?</h3>\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n                </div>\\n                <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0px;\\">\\n                  <div class=\\"mt-4\\" style=\\"padding-top: 0.5rem;\\">\\n                    <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">Go to Settings &gt; Billing and update your payment method, billing address, or view your payment history. All transactions are encrypted and secure.</p>\\n                  </div>\\n                </div>\\n              </div>\\n\\n              <!-- FAQ Item 4 -->\\n              <div class=\\"cursor-pointer border-b transition-all duration-300\\" style=\\"border-color: var(--border-color); padding-bottom: 1.5rem;\\" data-acc-item=\\"\\">\\n                <div class=\\"flex justify-between items-start gap-4\\" style=\\"cursor: pointer;\\">\\n                  <h3 class=\\"text-xl font-semibold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How do I upload a file or document?</h3>\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n                </div>\\n                <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                  <div class=\\"mt-4\\" style=\\"padding-top: 0.5rem;\\">\\n                    <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">Click the upload button in your dashboard, select your file, and wait for the upload to complete. Supported formats include PDF, DOC, JPG, and PNG up to 10MB.</p>\\n                  </div>\\n                </div>\\n              </div>\\n\\n              <!-- FAQ Item 5 -->\\n              <div class=\\"cursor-pointer border-b transition-all duration-300\\" style=\\"border-color: var(--border-color); padding-bottom: 1.5rem;\\" data-acc-item=\\"\\">\\n                <div class=\\"flex justify-between items-start gap-4\\" style=\\"cursor: pointer;\\">\\n                  <h3 class=\\"text-xl font-semibold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How do I delete my account?</h3>\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n                </div>\\n                <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                  <div class=\\"mt-4\\" style=\\"padding-top: 0.5rem;\\">\\n                    <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">Visit your account settings and select \\"Delete Account\\". Please note this action is permanent and will remove all your data from our system. Make sure to download any important information first.</p>\\n                  </div>\\n                </div>\\n              </div>\\n\\n              <!-- FAQ Item 6 -->\\n              <div class=\\"cursor-pointer border-b transition-all duration-300\\" style=\\"border-color: var(--border-color); padding-bottom: 1.5rem;\\" data-acc-item=\\"\\">\\n                <div class=\\"flex justify-between items-start gap-4\\" style=\\"cursor: pointer;\\">\\n                  <h3 class=\\"text-xl font-semibold\\" style=\\"color: var(--primary-text); font-family: var(--heading-font); position: relative;\\">How can I contact customer support?</h3>\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-down\\" class=\\"lucide lucide-chevron-down w-6 h-6 flex-shrink-0 transition-transform duration-300\\" style=\\"color: var(--primary-text); transform: rotate(0deg);\\" data-acc-icon=\\"rotate\\"><path d=\\"m6 9 6 6 6-6\\"></path></svg>\\n                </div>\\n                <div data-acc-content=\\"\\" class=\\"overflow-hidden transition-all duration-300 ease-in-out\\" style=\\"max-height: 0;\\">\\n                  <div class=\\"mt-4\\" style=\\"padding-top: 0.5rem;\\">\\n                    <p class=\\"text-base leading-relaxed\\" style=\\"color: var(--secondary-text); position: relative;\\">You can reach us through email, live chat, or phone support available 24/7. Our team typically responds within 2 hours during business hours.</p>\\n                  </div>\\n                </div>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"109"},{"html":"<section id=\\"fp-theme-collections\\" class=\\"min-h-screen flex items-center bg-themed-accent has-bg-image section\\" data-section=\\"10\\" data-bg=\\"accent\\" data-original-bg=\\"bg-themed-accent\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20\\">\\n          <div class=\\"grid md:grid-cols-2 gap-8\\">\\n            <div class=\\"relative group cursor-pointer\\">\\n              <div class=\\"relative overflow-hidden h-96\\" style=\\"border