"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"star\\" class=\\"lucide lucide-star w-6 h-6 fill-orange-500 text-orange-500\\"><path d=\\"M11.525 2.295a.53.53 0 0 1 .95 0l2.31 4.679a2.123 2.123 0 0 0 1.595 1.16l5.166.756a.53.53 0 0 1 .294.904l-3.736 3.638a2.123 2.123 0 0 0-.611 1.878l.882 5.14a.53.53 0 0 1-.771.56l-4.618-2.428a2.122 2.122 0 0 0-1.973 0L6.396 21.01a.53.53 0 0 1-.77-.56l.881-5.139a2.122 2.122 0 0 0-.611-1.879L2.16 9.795a.53.53 0 0 1 .294-.906l5.165-.755a2.122 2.122 0 0 0 1.597-1.16z\\"></path></svg>\\n                </div>\\n                <p class=\\"text-themed-secondary text-lg mb-6 leading-relaxed flex-1\\" style=\\"position: relative;\\">\\"I''ve tried numerous solutions over the years, but nothing comes close to this level of quality and support. The team truly understands their users'' needs and delivers exceptional value at every turn.\\"</p>\\n                <h3 class=\\"text-xl font-bold heading-themed\\" style=\\"position: relative;\\">James Washington</h3>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"26"},{"html":"<section id=\\"fp-theme-bio\\" class=\\"min-h-screen flex items-center bg-themed-primary has-bg-image section\\" data-section=\\"33\\" data-bg=\\"primary\\" data-original-bg=\\"bg-themed-primary\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20\\">\\n          <div class=\\"text-center mb-16\\">\\n            <h1 class=\\"text-4xl md:text-6xl font-bold heading-themed mb-12\\" style=\\"position: relative;\\">I am building a product that<br>can solve developer''s pain</h1>\\n          </div>\\n          <div class=\\"grid lg:grid-cols-2 gap-16 items-center max-w-6xl mx-auto\\">\\n            <div class=\\"order-2 lg:order-1\\">\\n              <img src=\\"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=600&amp;h=600&amp;fit=crop&amp;crop=face\\" alt=\\"John Smith - Founder\\" class=\\"w-full max-w-md mx-auto shadow-2xl\\" style=\\"border-radius: var(--card-radius);\\" loading=\\"lazy\\">\\n            </div>\\n            <div class=\\"order-1 lg:order-2 space-y-8\\">\\n              <div>\\n                <h3 class=\\"text-2xl font-bold heading-themed mb-4\\" style=\\"position: relative;\\">Hey! I am John, founder of ModernCo.</h3>\\n                <p class=\\"text-lg text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">After years of experiencing the frustrations that developers face daily, I decided to build something that could make a real difference. Our platform addresses the core challenges that slow teams down and prevent them from focusing on what they do best.</p>\\n              </div>\\n              <div>\\n                <p class=\\"text-lg text-themed-secondary leading-relaxed mb-8\\" style=\\"position: relative;\\">From managing complex workflows to collaborating across distributed teams, every feature we build is designed with the developer experience in mind. We believe that great tools should feel invisible, empowering you to create without getting in your way.</p>\\n                <h4 class=\\"text-xl font-bold heading-themed mb-4\\" style=\\"position: relative;\\">How do I do this without any investment?</h4>\\n                <p class=\\"text-lg text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">By staying lean, focusing on what matters most, and building with the community. Every line of code is written with purpose, every feature is validated with real users, and every decision is made with long-term sustainability in mind.</p>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"33"},{"html":"<section id=\\"fp-theme-team2\\" class=\\"min-h-screen flex items-center bg-themed-accent has-bg-image section\\" data-section=\\"35\\" 