\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"check\\" class=\\"lucide lucide-check w-5 h-5 text-white\\"><path d=\\"M20 6 9 17l-5-5\\"></path></svg>\\n                  </div>\\n                  <span class=\\"text-lg\\" style=\\"color: var(--primary-text); position: relative;\\">Suitable for use on any device</span>\\n                </div>\\n                <div class=\\"flex items-center space-x-4\\">\\n                  <div class=\\"w-8 h-8 rounded-full flex items-center justify-center\\" style=\\"background-color: var(--primary-accent);\\">\\n                    <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"check\\" class=\\"lucide lucide-check w-5 h-5 text-white\\"><path d=\\"M20 6 9 17l-5-5\\"></path></svg>\\n                  </div>\\n                  <span class=\\"text-lg\\" style=\\"color: var(--primary-text); position: relative;\\">Meetings can be started freely</span>\\n                </div>\\n              </div>\\n              <a href=\\"#\\" class=\\"inline-flex btn-themed text-lg px-8 py-4\\" style=\\"position: relative;\\">Download Application</a>\\n            </div>\\n            <div class=\\"relative flex justify-center\\">\\n              <!-- Phone Mockup SVG -->\\n              <div class=\\"relative\\">\\n                <svg width=\\"300\\" height=\\"600\\" viewBox=\\"0 0 300 600\\" class=\\"drop-shadow-2xl\\">\\n                  <!-- Phone Frame -->\\n                  <rect x=\\"10\\" y=\\"10\\" width=\\"280\\" height=\\"580\\" rx=\\"40\\" ry=\\"40\\" fill=\\"#000\\" stroke=\\"#333\\" stroke-width=\\"2\\"></rect>\\n                  <!-- Screen -->\\n                  <rect x=\\"25\\" y=\\"80\\" width=\\"250\\" height=\\"440\\" rx=\\"20\\" ry=\\"20\\" fill=\\"#f8f9fa\\"></rect>\\n                  <!-- Notch -->\\n                  <rect x