overflow-hidden\\" style=\\"background: linear-gradient(135deg, #60a5fa 0%, #3b82f6 100%);\\">\\n                    <img src=\\"https://images.unsplash.com/photo-1603891126434-03e2f6f67943?w=500&amp;h=500&amp;fit=crop\\" alt=\\"iPhone 16\\" class=\\"w-full h-80 object-cover mix-blend-multiply\\" style=\\"\\" loading=\\"lazy\\">\\n                  </div>\\n                  <h3 class=\\"text-2xl font-bold heading-themed mb-2 mt-8\\" style=\\"position: relative;\\">iPhone 16</h3>\\n                  <p class=\\"text-themed-secondary mb-4 text-base\\" style=\\"position: relative;\\">Amazing performance. Durable design.</p>\\n                  <p class=\\"text-lg font-semibold text-themed-primary mb-6\\" style=\\"position: relative;\\">From $699 or $29.12/mo. for 24 mo.</p>\\n                  <div class=\\"flex gap-4\\">\\n                    <button class=\\"btn-themed py-3 px-6 text-sm font-semibold\\" style=\\"position: relative;\\">Learn more</button>\\n                    <button class=\\"text-themed-accent hover:text-themed-accent/80 text-sm font-semibold flex items-center gap-1 transition-colors\\" style=\\"position: relative;\\">Buy<svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-right\\" class=\\"lucide lucide-chevron-right w-4 h-4\\"><path d=\\"m9 18 6-6-6-6\\"></path></svg></button>\\n                  </div>\\n                </div>\\n\\n                <!-- Product 5 -->\\n                <div class=\\"fp-keep-color flex-shrink-0 bg-themed-primary p-8 rounded-3xl\\" style=\\"width: 372px; border-radius: var(--card-radius); box-shadow: var(--shadow-md);\\">\\n                  <div class=\\"mb-6 rounded-2xl overflow-hidden\\" style=\\"background: linear-gradient(135deg, #fb7185 0%, #f43f5e 100%);\\">\\n                    <img src=\\"https://images.unsplash.com/photo-