.com/photo-1601784551446-20c9e07cdbdb?w=500&amp;h=500&amp;fit=crop\\" alt=\\"iPhone 15 Pro Max\\" class=\\"w-full h-80 object-cover mix-blend-multiply\\" style=\\"\\" loading=\\"lazy\\">\\n                  </div>\\n                  <h3 class=\\"text-2xl font-bold heading-themed mb-2 mt-8\\" style=\\"position: relative;\\">iPhone 15 Pro Max</h3>\\n                  <p class=\\"text-themed-secondary mb-4 text-base\\" style=\\"position: relative;\\">Ultimate performance with titanium design.</p>\\n                  <p class=\\"text-lg font-semibold text-themed-primary mb-6\\" style=\\"position: relative;\\">From $1199 or $49.95/mo. for 24 mo.</p>\\n                  <div class=\\"flex gap-4\\">\\n                    <button class=\\"btn-themed py-3 px-6 text-sm font-semibold\\" style=\\"position: relative;\\">Learn more</button>\\n                    <button class=\\"text-themed-accent hover:text-themed-accent/80 text-sm font-semibold flex items-center gap-1 transition-colors\\" style=\\"position: relative;\\">Buy<svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-right\\" class=\\"lucide lucide-chevron-right w-4 h-4\\"><path d=\\"m9 18 6-6-6-6\\"></path></svg></button>\\n                  </div>\\n                </div>\\n\\n                <!-- Product 7 -->\\n                <div class=\\"fp-keep-color flex-shrink-0 bg-themed-primary p-8 rounded-3xl\\" style=\\"width: 372px; border-radius: var(--card-radius); box-shadow: var(--shadow-md);\\">\\n                  <div class=\\"mb-6 rounded-2xl overflow-hidden\\" style=\\"background: linear-gradient(135deg, #fde047 0%, #facc15 100%);\\">\\n                    <img src=\\"https://images.unsplash.com/photo-1605236453806-6ff36851218e?w=500&amp;h=500&amp;fit=crop\\" alt=\\"iPhone 15\\" class=\\"w-full h-80 object-cover mix-blend-multiply\\" style=\\"\\" loading=\\"lazy\\">\\n                  </div>\\n                  <h3 class=\\"text-2xl font-bold heading-themed mb-2 mt-8\\" style=\\"position: relative;\\">iPhone 15</h3>\\n                  <p class=\\"text-themed-secondary mb-4 text-base\\" style=\\"position: relative;\\">Dynamic Island with a48 MP main camera.</p>\\n                  <p class=\\"text-lg font-semibold text-themed-primary mb-6\\" style=\\"position: relative;\\">From $899 or $37.45/mo. for 24 mo.</p>\\n                  <div class=\\"flex gap-4\\">\\n                    <button class=\\"btn-themed py-3 px-6 text-sm font-semibold\\" style=\\"position: relative;\\">Learn more</button>\\n                    <button class=\\"text-themed-accent hover:text-themed-accent/80 text-sm font-semibold flex items-center gap-1 transition-colors\\" style=\\"position: relative;\\">Buy<svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-right\\" class=\\"lucide lucide-chevron-right w-4 h-4\\"><path d=\\"m9 18 6-6-6-6\\"></path></svg></button>\\n                  </div>\\n                </div>\\n\\n                <!-- Product 8 -->\\n                <div class=\\"fp-keep-color flex-shrink-0 bg-themed-primary p-8 rounded-3xl\\" style=\\"width: 372px; border-radius: var(--card-radius); box-shadow: var(--shadow-md);\\">\\n                  <div class=\\"mb-6 rounded-2xl overflow-hidden\\" style=\\"background: linear-gradient(135deg, #34d399 0%, #10b981 100%);\\">\\n                    <img src=\\"https://images.unsplash.com/photo-1591337676887-a217a6970a8a?w=500&amp;h=500&amp;fit=crop\\" alt=\\"iPhone 14 Plus\\" class=\\"w-full h-80 object-cover mix-blend-multiply\\" style=\\"\\" loading=\\"lazy\\">\\n                  </div>\\n                  <h3 class=\\"text-2xl font-bold heading-themed mb-2 mt-8\\" style=\\"position: relative;\\">iPhone 14 Plus</h3>\\n                  <p class=\\"text-themed-secondary mb-4 text-base\\" style=\\"position: relative;\\">Big screen. Bigger battery. Best value.</p>\\n                  <p class=\\"text-lg font-semibold text-themed-primary mb-6\\" style=\\"position: relative;\\">From $799 or $33.29/mo. for 24 mo.</p>\\n                  <div class=\\"flex gap-4\\">\\n                    <button class=\\"btn-themed py-3 px-6 text-sm font-semibold\\" style=\\"position: relative;\\">Learn more</button>\\n                    <button class=\\"text-themed-accent hover:text-themed-accent/80 text-sm font-semibold flex items-center gap-1 transition-colors\\" style=\\"position: relative;\\">Buy<svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-right\\" class=\\"lucide lucide-chevron-right w-4 h-4\\"><path d=\\"m9 18 6-6-6-6\\"></path></svg></button>\\n                  </div>\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- Navigation Arrows -->\\n            <div class=\\"flex justify-end gap-4 max-w-7xl mx-auto mt-8 px-4 sm:px-6 lg:px-8\\">\\n              <button data-slider-prev=\\"\\" class=\\"p-3 rounded-full border-2 border-themed-primary hover:bg-themed-secondary transition-colors\\">\\n                <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-left\\" class=\\"lucide lucide-chevron-left w-6 h-6 text-themed-primary\\"><path d=\\"m15 18-6-6 6-6\\"></path></svg>\\n              </button>\\n              <button data-slider-next=\\"\\" class=\\"p-3 rounded-full border-2 border-themed-primary hover:bg-themed-secondary transitio