            </div>\\n          </div>\\n        </div>\\n      </section>","number":"93"},{"html":"<section id=\\"fp-theme-features-grid\\" class=\\"min-h-screen flex items-center bg-themed-primary has-bg-image section\\" data-section=\\"94\\" data-bg=\\"primary\\" data-original-bg=\\"bg-themed-primary\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20\\">\\n          <div class=\\"text-center mb-16\\">\\n            <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-6 heading-themed\\" style=\\"position: relative;\\">One Platform, Countless Benefits Save Time</h2>\\n            <p class=\\"text-lg md:text-xl max-w-3xl mx-auto text-themed-secondary\\" style=\\"position: relative;\\">We eliminate the need to juggle multiple applications, saving you valuable time and reducing complexity. Whether you''re managing projects or handling transactions.</p>\\n          </div>\\n\\n          <div class=\\"grid md:grid-cols-2 gap-12 items-center\\">\\n            <!-- Features Grid -->\\n            <div class=\\"grid sm:grid-cols-2 gap-8\\">\\n              <!-- Feature 1 -->\\n              <div class=\\"space-y-4\\">\\n                <div class=\\"w-14 h-14 flex items-center justify-center bg-themed-accent\\" style=\\"border-radius: var(--card-radius);\\">\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"credit-card\\" class=\\"lucide lucide-credit-card w-7 h-7 text-themed-primary\\"><rect width=\\"20\\" height=\\"14\\" x=\\"2\\" y=\\"5\\" rx=\\"2\\"></rect><line x1=\\"2\\" x2=\\"22\\" y1=\\"10\\" y2=\\"10\\"></line></svg>\\n                </div>\\n                <h3 class=\\"text-xl font-bold heading-themed\\" style=\\"position: relative;\\">Easy Payment</h3>\\n                <p class=\\"text-sm text-themed-secondary\\" style=\\"position: relative;\\">Easy payment solution, designed to streamline transactions and enhance convenience. Whether you''re a business owner.</p>\\n              </div>\\n\\n              <!-- Feature 2 -->\\n              <div class=\\"space-y-4\\">\\n                <div class=\\"w-14 h-14 flex items-center justify-center bg-themed-accent\\" style=\\"border-radius: var(--card-radius);\\">\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"shield-check\\" class=\\"lucide lucide-shield-check w-7 h-7 text-themed-primary\\"><path d=\\"M20 13c0 5-3.5 7.5-7.66 8.95a1 1 0 0 1-.67-.01C7.5 20.5 4 18 4 13V6a1 1 0 0 1 1-1c2 0 4.5-1.2 6.24-2.72a1.17 1.17 0 0 1 1.52 0C14.51 3.81 17 5 19 5a1 1 0 0 1 1 1z\\"></path><path d=\\"m9 12 2 2 4-4\\"></path></svg>\\n                </div>\\n                <h3 class=\\"text-xl font-bold heading-themed\\" style=\\"position: relative;\\">Safe Transaction</h3>\\n                <p class=\\"text-sm text-themed-secondary\\" style=\\"position: relative;\\">Our robust security measures protect your sensitive information and prevent unauthorized access.</p>\\n              </div>\\n\\n              <!-- Feature 3 -->\\n              <div class=\\"space-y-4\\">\\n                <div class=\\"w-14 h-14 flex items-center justify-center bg-themed-accent\\" style=\\"border-radius: var(--card-radius);\\">\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"headphones\\" class=\\"lucide lucide-headphones w-7 h-7 text-themed-primary\\"><path d=\\"M3 14h3a2 2 0 0 1 2 2v3a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-7a9 9 0 0 1 18 0v7a2 2 0 0 1-2