roke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"shield-check\\" class=\\"lucide lucide-shield-check w-8 h-8\\" style=\\"color: #22c55e;\\"><path d=\\"M20 13c0 5-3.5 7.5-7.66 8.95a1 1 0 0 1-.67-.01C7.5 20.5 4 18 4 13V6a1 1 0 0 1 1-1c2 0 4.5-1.2 6.24-2.72a1.17 1.17 0 0 1 1.52 0C14.51 3.81 17 5 19 5a1 1 0 0 1 1 1z\\"></path><path d=\\"m9 12 2 2 4-4\\"></path></svg>\\n                </div>\\n                <div class=\\"space-y-2\\">\\n                  <h3 class=\\"text-xl font-semibold text-themed-primary\\" style=\\"position: relative;\\">Bank-Grade Security</h3>\\n                  <p class=\\"text-base text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">End-to-end encryption, 2FA, compliance with GDPR standards.</p>\\n                </div>\\n              </div>\\n\\n              <!-- Feature 3: Customizable Reports -->\\n              <div class=\\"flex items-start gap-6 p-8 rounded-xl transition-all duration-300 hover:shadow-xl\\" style=\\"border-radius: var(--card-radius); background: transparent;\\" onmouseover=\\"this.style.background=''rgba(249, 115, 22, 0.1)''; this.style.borderColor=''rgba(249, 115, 22, 0.2)''; this.style.border=''1px solid'';\\" onmouseout=\\"this.style.background=''transparent''; this.style.border=''none'';\\">\\n                <div class=\\"flex-shrink-0\\">\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"download\\" class=\\"lucide lucide-download w-8 h-8\\" style=\\"color: #f97316;\\"><path d=\\"M12 15V3\\"></path><path d=\\"M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4\\"></path><path d=\\"m7 10 5 5 5-5\\"></path></svg>\\n                </div>\\n                <div class=\\"space-y-2\\">\\n                  <h3 class=\\"text-xl font-semibold text-themed-primary\\" style=\\"position: relative;\\">Customizable Reports</h3>\\n                  <p class=\\"text-base text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Export professional, audit-ready financial reports for tax or internal review.</p>\\n                </div>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"98"},{"html":"<section id=\\"fp-theme-phone-features\\" class=\\"min-h-screen has-bg-image section\\" style=\\"background: linear-gradient(135deg, rgba(139, 92, 246, 0.03) 0%, rgba(236, 72, 153, 0.03) 100%);\\" data-section=\\"100\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-24\\">\\n          <!-- Heading -->\\n          <div class=\\"text-center mb-16\\">\\n            <h2 class=\\"text-4xl md:text-5xl font-bold heading-themed mb-6\\" style=\\"position: relative;\\">Quickly build, share, <span class=\\"text-themed-accent\\">and launch</span> your perfect SaaS solution!</h2>\\n            <p class=\\"text-xl text-themed-secondary max-w-3xl mx-auto\\" style=\\"position: relative;\\">Using technology to make finance simpler, smarter and more rewarding.</p>\\n          </div>\\n\\n          <!-- Features Grid with Phone -->\\n          <div class=\\"grid lg:grid-cols-3 gap-12 items-center\\">\\n            <!-- Left Features -->\\n            <div class=\\"space-y-8\\">\\n              <!-- Feature 1: User Onboarding -->\\n              <div class=\\"flex items-start gap-4 lg:text-right lg:flex-row-reverse\\">\\n                <div class=\\"flex-shrink-0 p-4 rounded-2xl\\" style=\\"background: var(--accent-bg);\\">\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"calendar\\" class=