dient(135deg, var(--primary-accent), var(--secondary-accent));\\">\\n              <h3 class=\\"text-3xl font-bold text-white mb-3\\" style=\\"position: relative;\\">Michael Davidson</h3>\\n              <p class=\\"text-lg text-white mb-6 opacity-90\\" style=\\"position: relative;\\">Founder &amp; CEO</p>\\n              <p class=\\"text-base text-white mb-8 leading-relaxed max-w-md opacity-95\\" style=\\"position: relative;\\">Every step of the way, we''ve embraced challenges as opportunities, striving to surpass our limits and redefine excellence.</p>\\n              <div class=\\"flex gap-6\\">\\n                <a href=\\"#\\" class=\\"text-white hover:opacity-75 transition-opacity\\">\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"><path d=\\"M4 4l11.733 16h4.267l-11.733 -16z\\"></path><path d=\\"M4 20l6.768 -6.768m2.46 -2.46l6.772 -6.772\\"></path></svg>\\n                </a>\\n                <a href=\\"#\\" class=\\"text-white hover:opacity-75 transition-opacity\\">\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"><path d=\\"M18 2h-3a5 5 0 0 0-5 5v3H7v4h3v8h4v-8h3l1-4h-4V7a1 1 0 0 1 1-1h3z\\"></path></svg>\\n                </a>\\n                <a href=\\"#\\" class=\\"text-white hover:opacity-75 transition-opacity\\">\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"><rect width=\\"20\\" height=\\"20\\" x=\\"2\\" y=\\"2\\" rx=\\"5\\" ry=\\"5\\"></rect><path d=\\"M16 11.37A4 4 0 1 1 12.63 8 4 4 0 0 1 16 11.37z\\"></path><line x1=\\"17.5\\" x2=\\"17.51\\" y1=\\"6.5\\" y2=\\"6.5\\"></line></svg>\\n                </a>\\n              </div>\\n            </div>\\n\\n            <!-- Team Member 3 - Image -->\\n            <div class=\\"relative overflow-hidden\\" style=\\"aspect-ratio: 1/1; background: linear-gradient(135deg, rgba(196, 181, 253, 0.3), rgba(221, 214, 254, 0.5));\\">\\n              <img src=\\"./public/images/person-2.jpg\\" alt=\\"Robert Chen\\" class=\\"w-full h-full object-cover\\" style=\\"\\" loading=\\"lazy\\">\\n            </div>\\n\\n            <!-- Team Member 4 - Info Panel -->\\n            <div class=\\"relative flex flex-col items-center justify-center text-center px-8 py-12\\" style=\\"aspect-ratio: 1/1; background: linear-gradient(135deg, #4F46E5, #6366F1);\\">\\n              <h3 class=\\"text-3xl font-bold text-white mb-3\\" style=\\"position: relative;\\">Diana Foster</h3>\\n              <p class=\\"text-lg text-white mb-6 opacity-90\\" style=\\"position: relative;\\">Chief Operations Officer</p>\\n              <p class=\\"text-base text-white mb-8 leading-relaxed max-w-md opacity-95\\" style=\\"position: relative;\\">This venture represents not only a leap of faith but also a profound realization of a vision, transforming ideas into reality.</p>\\n              <div class=\\"flex gap-6\\">\\n                <a href=\\"#\\" class=\\"text-white hover:opacity-75 transition-opacity\\">\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\"><path d=\\"M4 4l11.733 16h4.267l-11.733 -16z\\"></path><path d=\\"M4 20l6.768 -6.768m2.46 -2.46l6.772 -6.772\\"></path></svg>\\n                </a>\\n                <a href=\\"#\\" class=\\"text-white hover:opacity-75 transition-opacity\\">\\n                  <svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"2