18\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\">\\n                  <path d=\\"M5 12h14\\"></path>\\n                  <path d=\\"m12 5 7 7-7 7\\"></path>\\n                </svg></a>\\n            </div>\\n\\n            <!-- Blog Card 2 - Square -->\\n            <div class=\\"group\\">\\n              <!-- Gradient Image -->\\n              <div class=\\"rounded-3xl overflow-hidden mb-6 h-64\\" style=\\"background: linear-gradient(135deg, #0f2027 0%, #203a43 30%, #2c5364 60%, #4ca1af 100%);\\">\\n                <div class=\\"w-full h-full flex items-center justify-center\\">\\n                  <div class=\\"w-24 h-24 rounded-full\\" style=\\"background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\\"></div>\\n                </div>\\n              </div>\\n              \\n              <!-- Content -->\\n              <h3 class=\\"text-base md:text-lg font-bold heading-themed mb-3 leading-tight\\" style=\\"position: relative;\\">Tech-Enhanced Journeys: How the Travel Industry Embraces.</h3>\\n              <p class=\\"text-themed-secondary text-sm mb-4 leading-relaxed\\" style=\\"position: relative;\\">Discover how the travel industry is transforming with cutting-edge.</p>\\n              \\n              <!-- Read More Link -->\\n              <a href=\\"#\\" class=\\"inline-flex items-center gap-2 text-sm font-semibold transition-all duration-300 hover:gap-3\\" style=\\"color: var(--primary-accent); position: relative;\\">Read more\\n<svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"18\\" height=\\"18\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\">\\n                  <path d=\\"M5 12h14\\"></path>\\n                  <path d=\\"m12 5 7 7-7 7\\"></path>\\n                </svg></a>\\n            </div>\\n\\n            <!-- Blog Card 3 - Square -->\\n   