n                  <textarea placeholder=\\"Message\\" rows=\\"4\\" class=\\"w-full px-6 py-4 text-lg rounded-2xl focus:outline-none resize-none\\" style=\\"background: var(--secondary-bg); color: var(--primary-text); border: 2px solid rgba(139, 92, 246, 0.3);\\"></textarea>\\n                </div>\\n                <button type=\\"submit\\" class=\\"w-full px-8 py-4 text-lg font-semibold text-white rounded-full\\" style=\\"background: var(--accent-color); position: relative;\\">Submit</button><input type=\\"hidden\\" name=\\"tinymce-a7bbj8uvy\\">\\n              </form>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"134"},{"html":"<section id=\\"fp-theme-integrations-cards\\" class=\\"min-h-screen flex items-center has-bg-image section\\" style=\\"background: var(--primary-bg);\\" data-section=\\"135\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"w-full max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20\\">\\n          <!-- Header -->\\n          <div class=\\"text-center mb-16 max-w-4xl mx-auto\\">\\n            <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-6 heading-themed\\" style=\\"position: relative;\\">Integrations</h2>\\n            <p class=\\"text-xl md:text-2xl text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Integrations refer to the process of combining different software systems or components to work together seamlessly. This involves connecting various applications.</p>\\n          </div>\\n\\n          <!-- Integration Cards Grid -->\\n          <div class=\\"grid md:grid-cols-2 lg:grid-cols-4 gap-8\\">\\n            <!-- Card 1 - Analytics -->\\n            <div class=\\"card-themed p-4 text-center transition-all duration-300 hover:shadow-xl hover:-translate-y-2\\" style=\\"border-radius: var(--card-radius);\\">\\n              <img src=\\"public/logos/svg/logo-1.svg\\" alt=\\"Analytics\\" class=\\"mx-auto mb-6 object-contain\\" style=\\"max-width: 45px; max-height: 45px;\\" loading=\\"lazy\\">\\n              <h3 class=\\"text-xl font-bold mb-4 heading-themed\\" style=\\"position: relative;\\">Analytics</h3>\\n              <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Analytics is a powerful data visualization platform designed to help you track metrics and gain insights</p>\\n            </div>\\n\\n            <!-- Card 2 - Payments -->\\n            <div class=\\"card-themed p-4 text-center transition-all duration-300 hover:shadow-xl hover:-translate-y-2\\" style=\\"border-radius: var(--card-radius);\\">\\n              <img src=\\"public/logos/svg/logo-2.svg\\" alt=\\"Payments\\" class=\\"mx-auto mb-6 object-contain\\" style=\\"max-width: 45px; max-height: 45px;\\" loading=\\"lazy\\">\\n              <h3 class=\\"text-xl font-bold mb-4 heading-themed\\" style=\\"position: relative;\\">Payments</h3>\\n              <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Payments is a comprehensive payment processing solution for the entire customer transaction lifecycle</p>\\n            </div>\\n\\n            <!-- Card 3 - Communication -->\\n            <div class=\\"card-themed p-4 text-center transition-all duration-300 hover:shadow-xl hover:-translate-y-2\\" style=\\"border-radius: var(--card-radius);\\">\\n              <img src=\\"public/logos/svg/logo-3.svg\\" alt=\\"Communication\\" class=\\"mx-auto mb-6 object-contain\\" style=\\"max-width: 45px; max-height: 45px;\\" loading=\\"lazy\\">\\n              <h3 class=\\"text-xl font-bold mb-4 heading-themed\\" style=\\"position: relative;\\">Communication</h3>\\n              <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Communication is a real-time messaging service that offers users instant chat and collaboration features</p>\\n            </div>\\n\\n            <!-- Card 4 - Storage -->\\n            <div class=\\"card-themed p-4 text-center transition-all duration-300 hover:shadow-xl hover:-translate-y-2\\" style=\\"border-radius: var(--card-radius);\\">\\n              <img src=\\"public/logos/svg/logo-4.svg\\" alt=\\"Storage\\" class=\\"mx-auto mb-6 object-contain\\" style=\\"max-width: 45px; max-height: 45px;\\" loading=\\"lazy\\">\\n              <h3 class=\\"text-xl font-bold mb-4 heading-themed\\" style=\\"position: relative;\\">Storage</h3>\\n              <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Storage is an open-source platform for developing cloud storage components in isolation for modern apps</p>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"135"},{"html":"<section id=\\"fp-theme-numbers-split\\" class=\\"min-h-screen flex items-center has-bg-image section\\" style=\\"background: var(--section-bg);\\" data-section=\\"136\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 w-full\\">\\n          <div class=\\"grid lg:grid-cols-2 gap-16 items-center\\">\\n            <!-- Left Column: Heading + Image -->\\n            <div class=\\"space-y-8\\">\\n               <h2 class=\\"text-3xl md:text-4xl lg:text-5xl font-bold leading-tight\\" style=\\"font-family: var(--heading-font); position: relative;\\"><span class=\\"heading-themed\\">The Art of</span> <span style=\\"color: var(--primary-accent);\\"> Innovation</span><br><span class=\\"heading-themed\\">Building Solutions.</span></h2>\\n              \\n              <div class=\\"relative overflow-hidden shadow-2xl\\" style=\\"border-radius: var(--card-radius);\\">\\n                <img src=\\"https://images.unsplash.com/photo-1497366216548-37526070297c?w=800&amp;h=600&amp;fit=crop\\" alt=\\"Modern workspace\\" class=\\"w-full h-auto object-cover\\" style=\\"\\" loading=\\"lazy\\">\\n              </div>\\n            </div>\\n\\n            <!-- Right Column: Subheading + Text + Stats -->\\n            <div class=\\"space-y-8\\">\\n              <div>\\n                <h3 class=\\"text-2xl md:text-3xl font-bold mb-4 heading-themed\\" style=\\"font-family: var(--heading-font); position: relative;\\">Excellence Through Innovation</h3>\\n                <p class=\\"text-lg text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">This section showcases the remarkable achievements and milestones that define our commitment to excellence. From groundbreaking projects to satisfied clients, discover the numbers that tell our story of success and innovation.</p>\\n              </div>\\n\\n              <!-- Stats Grid -->\\n              <div class=\\"fp-keep-color grid grid-cols-2 gap-6\\">\\n                <!-- Stat 1 -->\\n                <div class=\\"card-themed p-8\\" style=\\"border-radius: var(--card-radius);\\">\\n                  <h4 class=\\"text-4xl md:text-5xl font-bold mb-2\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">15k+</h4>\\n                  <p class=\\"text-themed-secondary text-lg\\" style=\\"position: relative;\\">Satisfied Clients</p>\\n                </div>\\n\\n                <!-- Stat 2 -->\\n                <div class=\\"card-themed p-8\\" style=\\"border-radius: var(--card-radius);\\">\\n                  <h4 class=\\"text-4xl md:text-5xl font-bold mb-2\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">22+</h4>\\n                  <p class=\\"text-themed-secondary text-lg\\" style=\\"position: relative;\\">Years of Excellence</p>\\n                </div>\\n\\n                <!-- Stat 3 -->\\n                <div class=\\"card-themed p-8\\" style=\\"border-radius: var(--card-radius);\\">\\n                  <h4 class=\\"text-4xl md:text-5xl font-bold mb-2\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">8+</h4>\\n                  <p class=\\"text-themed-secondary text-lg\\" style=\\"position: relative;\\">Industry Awards</p>\\n                </div>\\n\\n                <!-- Stat 4 -->\\n                <div class=\\"card-themed p-8\\" style=\\"border-radius: var(--card-radius);\\">\\n                  <h4 class=\\"text-4xl md:text-5xl font-bold mb-2\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">35+</h4>\\n                  <p class=\\"text-themed-secondary text-lg\\" style=\\"position: relative;\\">Global Projects</p>\\n                </div>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"136"},{"html":"<section id=\\"fp-theme-numbers-centered\\" class=\\"min-h-screen flex items-center has-bg-image section\\" style=\\"background: var(--section-bg);\\" data-section=\\"137\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 w-full\\">\\n          <!-- Small Heading -->\\n          <p class=\\"text-center text-lg mb-6\\" style=\\"color: var(--primary-accent); font-weight: 500; position: relative;\\">About Us</p>\\n          \\n          <!-- Main Heading -->\\n           <h2 class=\\"text-3xl md:text-4xl lg:text-5xl font-bold mb-8 text-center heading-themed\\" style=\\"font-family: var(--heading-font); position: relative;\\">Delivering Excellence Through Innovation</h2>\\n          \\n          <!-- Description -->\\n          <p class=\\"text-lg text-themed-secondary text-center max-w-4xl mx-auto mb-16 leading-relaxed\\" style=\\"position: relative;\\">Our projects stand out through our commitment to exceptional digital solutions. We approach each challenge with a fresh perspective, employing cutting-edge technologies and customized strategies that drive real results.</p>\\n          \\n          <!-- Stats Grid -->\\n          <div class=\\"grid grid-cols-2 md:grid-cols-4 gap-8 mb-16\\">\\n            <!-- Stat 1 -->\\n            <div class=\\"text-center\\">\\n              <h3 class=\\"text-4xl md:text-5xl font-bold mb-3\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">18+</h3>\\n              <p class=\\"text-lg text-themed-secondary\\" style=\\"position: relative;\\">Years of Experience</p>\\n            </div>\\n            \\n            <!-- Stat 2 -->\\n            <div class=\\"text-center\\">\\n              <h3 class=\\"text-4xl md:text-5xl font-bold mb-3\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">75+</h3>\\n              <p class=\\"text-lg text-themed-secondary\\" style=\\"position: relative;\\">Expert Team Members</p>\\n            </div>\\n            \\n            <!-- Stat 3 -->\\n            <div class=\\"text-center\\">\\n              <h3 class=\\"text-4xl md:text-5xl font-bold mb-3\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">52+</h3>\\n              <p class=\\"text-lg text-themed-secondary\\" style=\\"position: relative;\\">Successful Projects</p>\\n            </div>\\n            \\n            <!-- Stat 4 -->\\n            <div class=\\"text-center\\">\\n              <h3 class=\\"text-4xl md:text-5xl font-bold mb-3\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">48+</h3>\\n              <p class=\\"text-lg text-themed-secondary\\" style=\\"position: relative;\\">Happy Clients</p>\\n            </div>\\n          </div>\\n          \\n          <!-- Large Image -->\\n          <div class=\\"relative overflow-hidden shadow-2xl\\" style=\\"border-radius: var(--card-radius);\\">\\n            <img src=\\"https://images.unsplash.com/photo-1541888946425-d81bb19240f5?w=1400&amp;h=600&amp;fit=crop\\" alt=\\"Modern technology workspace\\" class=\\"w-full h-auto object-cover\\" style=\\"\\" loading=\\"lazy\\">\\n          </div>\\n        </div>\\n      </section>","number":"137"},{"html":"<section id=\\"fp-theme-numbers-with-features\\" class=\\"min-h-screen flex items-center has-bg-image section\\" style=\\"background: var(--section-bg);\\" data-section=\\"138\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 w-full\\">\\n          <div class=\\"grid lg:grid-cols-2 gap-12 items-center\\">\\n            <!-- Left Column: Content -->\\n            <div>\\n              <!-- Small Heading -->\\n              <p class=\\"text-sm mb-4\\" style=\\"color: var(--primary-accent); font-weight: 500; position: relative;\\">A little about us</p>\\n              \\n              <!-- Main Heading -->\\n              <h2 class=\\"text-3xl md:text-4xl lg:text-5xl font-bold mb-6 heading-themed\\" style=\\"font-family: var(--heading-font); position: relative;\\">Simple Yet Effective Strategies for Financial Success.</h2>\\n              \\n              <!-- Description -->\\n              <p class=\\"text-base text-themed-secondary mb-8 leading-relaxed\\" style=\\"position: relative;\\">the creation of environments where everyone has the opportunity to thrive. This approach not only promotes individual success but also contributes to the overall resilience and cohesion of society.</p>\\n              \\n              <!-- Features List with Checkmarks -->\\n              <div class=\\"space-y-5 mb-10\\">\\n                <div class=\\"flex items-center gap-3\\">\\n                  <div class=\\"flex-shrink-0 w-6 h-6 rounded-full flex items-center justify-center\\" style=\\"background: var(--primary-accent);\\">\\n                    <svg class=\\"w-4 h-4 text-white\\" fill=\\"none\\" stroke=\\"currentColor\\" viewBox=\\"0 0 24 24\\">\\n                      <path stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" stroke-width=\\"3\\" d=\\"M5 13l4 4L19 7\\"></path>\\n                    </svg>\\n                  </div>\\n                  <p class=\\"text-base text-themed-secondary\\" style=\\"position: relative;\\">More than 10 years of experience.</p>\\n                </div>\\n                \\n                <div class=\\"flex items-center gap-3\\">\\n                  <div class=\\"flex-shrink-0 w-6 h-6 rounded-full flex items-center justify-center\\" style=\\"background: var(--primary-accent);\\">\\n                    <svg class=\\"w-4 h-4 text-white\\" fill=\\"none\\" stroke=\\"currentColor\\" viewBox=\\"0 0 24 24\\">\\n                      <path stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" stroke-width=\\"3\\" d=\\"M5 13l4 4L19 7\\"></path>\\n                    </svg>\\n                  </div>\\n                  <p class=\\"text-base text-themed-secondary\\" style=\\"position: relative;\\">Over 100k happy customers and finished projects.</p>\\n                </div>\\n                \\n                <div class=\\"flex items-center gap-3\\">\\n                  <div class=\\"flex-shrink-0 w-6 h-6 rounded-full flex items-center justify-center\\" style=\\"background: var(--primary-accent);\\">\\n                    <svg class=\\"w-4 h-4 text-white\\" fill=\\"none\\" stroke=\\"currentColor\\" viewBox=\\"0 0 24 24\\">\\n                      <path stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" stroke-width=\\"3\\" d=\\"M5 13l4 4L19 7\\"></path>\\n                    </svg>\\n                  </div>\\n                  <p class=\\"text-base text-themed-secondary\\" style=\\"position: relative;\\">It has 20 branches around the world.</p>\\n                </div>\\n                \\n                <div class=\\"flex items-center gap-3\\">\\n                  <div class=\\"flex-shrink-0 w-6 h-6 rounded-full flex items-center justify-center\\" style=\\"background: var(--primary-accent);\\">\\n                    <svg class=\\"w-4 h-4 text-white\\" fill=\\"none\\" stroke=\\"currentColor\\" viewBox=\\"0 0 24 24\\">\\n                      <path stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" stroke-width=\\"3\\" d=\\"M5 13l4 4L19 7\\"></path>\\n                    </svg>\\n                  </div>\\n                  <p class=\\"text-base text-themed-secondary\\" style=\\"position: relative;\\">60 Team members are individuals</p>\\n                </div>\\n              </div>\\n              \\n              <!-- CTA Button -->\\n              <button class=\\"btn-themed px-8 py-4 text-base font-semibold\\" style=\\"position: relative;\\">Get Started</button>\\n            </div>\\n            \\n            <!-- Right Column: Image with Overlay Stats -->\\n            <div class=\\"relative overflow-hidden shadow-2xl\\" style=\\"border-radius: var(--card-radius); min-height: 600px;\\">\\n              <!-- Background Image -->\\n              <img src=\\"https://images.unsplash.com/photo-1497366216548-37526070297c?w=1200&amp;h=800&amp;fit=crop\\" alt=\\"Modern office workspace\\" class=\\"w-full h-full object-cover absolute inset-0\\" style=\\"\\" loading=\\"lazy\\">\\n              \\n              <!-- Overlay Gradient -->\\n              <div class=\\"absolute inset-0 bg-gradient-to-b from-black/60 via-transparent to-black/80\\"></div>\\n              \\n              <!-- Top Content -->\\n              <div class=\\"absolute top-8 left-8 right-8\\">\\n                <p class=\\"text-white/90 text-sm font-semibold mb-2 uppercase tracking-wider\\" style=\\"position: relative;\\">About us</p>\\n                <h3 class=\\"text-white text-2xl md:text-3xl font-bold leading-tight\\" style=\\"position: relative;\\">Achieve Financial Success with These Simple Effective</h3>\\n              </div>\\n              \\n              <!-- Bottom Stats -->\\n              <div class=\\"absolute bottom-0 left-0 right-0 grid grid-cols-3 divide-x divide-white/20\\">\\n                <div class=\\"px-6 py-8 text-center\\">\\n                  <h4 class=\\"text-2xl md:text-3xl font-bold text-white mb-2\\" style=\\"position: relative;\\">5.6M+</h4>\\n                  <p class=\\"text-white text-sm md:text-base\\" style=\\"opacity: 0.85; position: relative;\\">Downloads</p>\\n                </div>\\n                \\n                <div class=\\"px-6 py-8 text-center\\">\\n                  <h4 class=\\"text-2xl md:text-3xl font-bold text-white mb-2\\" style=\\"position: relative;\\">3.2+</h4>\\n                  <p class=\\"text-white text-sm md:text-base\\" style=\\"opacity: 0.85; position: relative;\\">Active Users</p>\\n                </div>\\n                \\n                <div class=\\"px-6 py-8 text-center\\">\\n                  <h4 class=\\"text-2xl md:text-3xl font-bold text-white mb-2\\" style=\\"position: relative;\\">4.9</h4>\\n                  <p class=\\"text-white text-sm md:text-base\\" style=\\"opacity: 0.85; position: relative;\\">Ratings</p>\\n                </div>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"138"},{"html":"<section id=\\"fp-theme-numbers-performance\\" class=\\"min-h-screen flex items-center has-bg-image section\\" style=\\"background: var(--primary-bg);\\" data-section=\\"139\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 w-full\\">\\n          <!-- Small Heading -->\\n          <p class=\\"text-center text-sm font-semibold mb-4 uppercase tracking-wider text-themed-secondary\\" style=\\"position: relative;\\">About Us</p>\\n          \\n          <!-- Main Heading -->\\n          <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-16 text-center heading-themed\\" style=\\"font-family: var(--heading-font); position: relative;\\">Understanding Your Performance Data</h2>\\n          \\n          <!-- Two Column Layout -->\\n          <div class=\\"grid lg:gr