cols-2 md:grid-cols-4 gap-6\\">\\n            <!-- Stat 1 - Blue -->\\n            <div class=\\"card-themed p-8 text-center hover-scale\\">\\n              <div class=\\"w-16 h-16 mx-auto mb-6 flex items-center justify-center\\">\\n                <svg class=\\"w-12 h-12\\" style=\\"color: #3B82F6;\\" fill=\\"none\\" stroke=\\"currentColor\\" viewBox=\\"0 0 24 24\\">\\n                  <path stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" stroke-width=\\"1.5\\" d=\\"M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z\\"></path>\\n                </svg>\\n              </div>\\n              <h4 class=\\"text-4xl md:text-5xl font-bold mb-3 heading-themed\\" style=\\"font-family: var(--heading-font); position: relative;\\">260+</h4>\\n              <p class=\\"text-themed-secondary text-base\\" style=\\"position: relative;\\">Expert Consultants</p>\\n            </div>\\n            \\n            <!-- Stat 2 - Green -->\\n            <div class=\\"card-themed p-8 text-center hover-scale\\">\\n              <div class=\\"w-16 h-16 mx-auto mb-6 flex items-center justify-center\\">\\n                <svg class=\\"w-12 h-12\\" style=\\"color: #10B981;\\" fill=\\"none\\" stroke=\\"currentColor\\" viewBox=\\"0 0 24 24\\">\\n                  <path stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" stroke-width=\\"1.5\\" d=\\"M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z\\"></path>\\n                </svg>\\n              </div>\\n              <h4 class=\\"text-4xl md:text-5xl font-bold mb-3 heading-themed\\" style=\\"font-family: var(--heading-font); position: relative;\\">975+</h4>\\n              <p class=\\"text-themed-secondary text-base\\" style=\\"position: relative;\\">Active Clients</p>\\n            </div>\\n            \\n            <!-- Stat 3 - Orange -->\\n            <div class=\\"card-themed p-8 text-center hover-scale\\">\\n              <div class=\\"w-16 h-16 mx-auto mb-6 flex items-center justify-center\\">\\n                <svg class=\\"w-12 h-12\\" style=\\"color: #F59E0B;\\" fill=\\"none\\" stroke=\\"currentColor\\" viewBox=\\"0 0 24 24\\">\\n                  <path stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" stroke-width=\\"1.5\\" d=\\"M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z\\"></path>\\n                </svg>\\n              </div>\\n              <h4 class=\\"text-4xl md:text-5xl font-bold mb-3 heading-themed\\" style=\\"font-family: var(--heading-font); position: relative;\\">724+</h4>\\n              <p class=\\"text-themed-secondary text-base\\" style=\\"position: relative;\\">Projects Delivered</p>\\n            </div>\\n            \\n            <!-- Stat 4 - Purple -->\\n            <div class=\\"card-themed p-8 text-center hover-scale\\">\\n              <div class=\\"w-16 h-16 mx-auto mb-6 flex items-center justify-center\\">\\n                <svg class=\\"w-12 h-12\\" style=\\"color: #6366F1;\\" fill=\\"none\\" stroke=\\"currentColor\\" viewBox=\\"0 0 24 24\\">\\n                  <path stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" stroke-width=\\"1.5\\" d=\\"M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z\\"></path>\\n                </svg>\\n              </div>\\n              <h4 class=\\"text-4xl md:text-5xl font-bold mb-3 heading-themed\\" style=\\"font-family: var(--heading-font); position: relative;\\">89+</h4>\\n              <p class=\\"text-themed-secondary text-base\\" style=\\"position: relative;\\">Orders in Queue</p>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"139"},{"html":"<section id=\\"fp-theme-integrations\\" class=\\"min-h-screen flex items-center has-bg-image section\\" style=\\"background: var(--