  <h2 class=\\"text-3xl md:text-4xl lg:text-5xl font-bold mb-12 text-center heading-themed\\" style=\\"font-family: var(--heading-font); position: relative;\\">Innovative Solutions for a Smoother</h2>\\n          \\n          <!-- Two Images Grid -->\\n          <div class=\\"grid md:grid-cols-2 gap-8 mb-12\\">\\n            <div class=\\"relative overflow-hidden\\" style=\\"border-radius: var(--card-radius);\\">\\n              <img src=\\"https://images.unsplash.com/photo-1522071820081-009f0129c71c?w=800&amp;h=600&amp;fit=crop\\" alt=\\"Team collaboration\\" class=\\"w-full h-[400px] object-cover\\" style=\\"\\" loading=\\"lazy\\">\\n            </div>\\n            <div class=\\"relative overflow-hidden\\" style=\\"border-radius: var(--card-radius);\\">\\n              <img src=\\"https://images.unsplash.com/photo-1600880292203-757bb62b4baf?w=800&amp;h=600&amp;fit=crop\\" alt=\\"Team meeting\\" class=\\"w-full h-[400px] object-cover\\" style=\\"\\" loading=\\"lazy\\">\\n            </div>\\n          </div>\\n\\n          <!-- Content Below Images -->\\n          <div class=\\"grid md:grid-cols-2 gap-12 mb-16\\">\\n            <div>\\n              <h3 class=\\"text-2xl md:text-3xl lg:text-4xl font-bold heading-themed\\" style=\\"font-family: var(--heading-font); position: relative;\\">Innovative Solutions, Efficient Life</h3>\\n            </div>\\n            <div class=\\"flex items-center\\">\\n              <p class=\\"text-lg text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Finding ways to simplify daily tasks is essential for achieving a more balanced and productive life. Our guide to innovative solutions offers practical strategies and cutting-edge technologies designed</p>\\n            </div>\\n          </div>\\n\\n          <!-- Stats Grid -->\\n          <div class=\\"grid grid-cols-2 md:grid-cols-4 gap-8\\">\\n            <!-- Stat 1 -->\\n            <div class=\\"text-center\\">\\n              <h3 class=\\"text-4xl md:text-5xl font-bold mb-3\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">25+</h3>\\n              <p class=\\"text-lg text-themed-secondary\\" style=\\"position: relative;\\">Years of Experience</p>\\n            </div>\\n            \\n            <!-- Stat 2 -->\\n            <div class=\\"text-center\\">\\n              <h3 class=\\"text-4xl md:text-5xl font-bold mb-3\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">90+</h3>\\n              <p class=\\"text-lg text-themed-secondary\\" style=\\"position: relative;\\">Team Members</p>\\n            </div>\\n            \\n            <!-- Stat 3 -->\\n            <div class=\\"text-center\\">\\n              <h3 class=\\"text-4xl md:text-5xl font-bold mb-3\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">64+</h3>\\n              <p class=\\"text-lg text-themed-secondary\\" style=\\"position: relative;\\">Successful Projects</p>\\n            </div>\\n            \\n            <!-- Stat 4 -->\\n            <div class=\\"text-center\\">\\n              <h3 class=\\"text-4xl md:text-5xl font-bold mb-3\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">60+</h3>\\n              <p class=\\"text-lg text-themed-secondary\\" style=\\"position: relative;\\">Happy Clients</p>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"141"},{"html":"<section id=\\"fp-theme-property-experts\\" class=\\"min-h-screen flex items-center bg-themed-primary has-bg-image section\\" data-section=\\"142\\" data-bg=\\"primary\\" data-original-bg=\\"bg-themed-primary\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 w-full\\">\\n          <!-- Top Section - Heading and Description -->\\n          <div class=\\"mb-16\\">\\n            <div class=\\"grid lg:grid-cols-2 gap-16 items-start\\">\\n              <!-- Heading -->\\n              <div>\\n                <h2 class=\\"text-3xl md:text-4xl lg:text-5xl font-bold heading-themed\\" style=\\"font-family: var(--heading-font); position: relative;\\">Your Dedicated Property Experts</h2>\\n              </div>\\n              \\n              <!-- Description -->\\n              <div>\\n                <p class=\\"text-lg md:text-xl text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">A real estate agent providing a smooth way to find your dream home in the heart of the city. With our expert guidance, your perfect home is just a step away.</p>\\n              </div>\\n            </div>\\n          </div>\\n          \\n          <!-- Bottom Section - Stats and Content Card -->\\n          <div class=\\"flex flex-col lg:flex-row gap-8\\">\\n            <!-- Left Side - 4 Stats in 2x2 Grid -->\\n            <div class=\\"flex-1\\">\\n              <div class=\\"fp-keep-color grid grid-cols-2 gap-6 h-full\\">\\n                <!-- Stat 1 -->\\n                <div class=\\"card-themed p-8 hover:shadow-lg transition-all duration-300 flex flex-col justify-center\\" style=\\"border-radius: var(--card-radius);\\">\\n                  <h3 class=\\"text-4xl md:text-5xl font-bold mb-3 text-center\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">20k+</h3>\\n                  <p class=\\"text-lg text-themed-secondary text-center\\" style=\\"position: relative;\\">Satisfied Customer</p>\\n                </div>\\n                \\n                <!-- Stat 2 -->\\n                <div class=\\"card-themed p-8 hover:shadow-lg transition-all duration-300 flex flex-col justify-center\\" style=\\"border-radius: var(--card-radius);\\">\\n                  <h3 class=\\"text-4xl md:text-5xl font-bold mb-3 text-center\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">28+</h3>\\n                  <p class=\\"text-lg text-themed-secondary text-center\\" style=\\"position: relative;\\">Year of Experience</p>\\n                </div>\\n                \\n                <!-- Stat 3 -->\\n                <div class=\\"card-themed p-8 hover:shadow-lg transition-all duration-300 flex flex-col justify-center\\" style=\\"border-radius: var(--card-radius);\\">\\n                  <h3 class=\\"text-4xl md:text-5xl font-bold mb-3 text-center\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">10+</h3>\\n                  <p class=\\"text-lg text-themed-secondary text-center\\" style=\\"position: relative;\\">Award Winning</p>\\n                </div>\\n                \\n                <!-- Stat 4 -->\\n                <div class=\\"card-themed p-8 hover:shadow-lg transition-all duration-300 flex flex-col justify-center\\" style=\\"border-radius: var(--card-radius);\\">\\n                  <h3 class=\\"text-4xl md:text-5xl font-bold mb-3 text-center\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">42+</h3>\\n                  <p class=\\"text-lg text-themed-secondary text-center\\" style=\\"position: relative;\\">Property Collection</p>\\n                </div>\\n              </div>\\n            </div>\\n            \\n            <!-- Right Side - Large Content Card with Image -->\\n            <div class=\\"flex-1\\">\\n              <div class=\\"fp-keep-color card-themed p-8 h-full flex flex-col\\" style=\\"border-radius: var(--card-radius);\\">\\n                <div class=\\"flex-1 flex flex-col lg:flex-row gap-8\\">\\n                  <!-- Text Content -->\\n                  <div class=\\"flex-1 flex flex-col justify-center\\">\\n                    <p class=\\"text-lg text-themed-secondary leading-relaxed mb-6\\" style=\\"position: relative;\\">We have observed the constantly changing real estate market and have become a trusted partner for thousands of clients. Our commitment to excellence and personalized service has earned us their loyalty and confidence.</p>\\n                    \\n                    <!-- Show More Link -->\\n                    <a href=\\"#\\" class=\\"inline-flex items-center gap-2 font-semibold text-lg group self-start text-themed-primary-accent\\" style=\\"position: relative;\\">Show More &gt;&gt;</a>\\n                  </div>\\n                  \\n                  <!-- Property Image -->\\n                  <div class=\\"flex-1 relative overflow-hidden\\" style=\\"border-radius: var(--card-radius);\\">\\n                    <img src=\\"https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?w=800&amp;h=600&amp;fit=crop\\" alt=\\"Modern Property\\" class=\\"w-full h-full object-cover hover:scale-105 transition-transform duration-500\\" style=\\"\\" loading=\\"lazy\\">\\n                  </div>\\n                </div>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"142"},{"html":"<section id=\\"fp-theme-empowering-communities\\" class=\\"min-h-screen flex items-center bg-themed-primary has-bg-image section\\" data-section=\\"143\\" data-bg=\\"primary\\" data-original-bg=\\"bg-themed-primary\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 w-full\\">\\n          <div class=\\"grid lg:grid-cols-2 gap-16 items-center\\">\\n            <!-- Left Column: Content -->\\n            <div>\\n              <!-- Small Heading -->\\n              <p class=\\"text-sm mb-4 text-themed-secondary font-medium\\" style=\\"position: relative;\\">A little about us</p>\\n              \\n              <!-- Main Heading -->\\n              <h2 class=\\"text-3xl md:text-4xl lg:text-5xl font-bold mb-6 heading-themed\\" style=\\"font-family: var(--heading-font); position: relative;\\">Empowering Communities Together</h2>\\n              \\n              <!-- Description -->\\n              <p class=\\"text-base md:text-lg text-themed-secondary mb-10 leading-relaxed\\" style=\\"position: relative;\\">the creation of environments where everyone has the opportunity to thrive. This approach not only promotes individual success but also contributes to the overall resilience and cohesion of society.</p>\\n              \\n              <!-- Features List with Checkmarks -->\\n              <div class=\\"space-y-5 mb-10\\">\\n                <div class=\\"flex items-center gap-3\\">\\n                  <div class=\\"flex-shrink-0 w-6 h-6 rounded-full flex items-center justify-center\\" style=\\"background: var(--primary-accent);\\">\\n                    <svg class=\\"w-4 h-4 text-white\\" fill=\\"none\\" stroke=\\"currentColor\\" viewBox=\\"0 0 24 24\\">\\n                      <path stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" stroke-width=\\"3\\" d=\\"M5 13l4 4L19 7\\"></path>\\n                    </svg>\\n                  </div>\\n                  <p class=\\"text-base text-themed-secondary\\" style=\\"position: relative;\\">More than 10 years of experience.</p>\\n                </div>\\n                \\n                <div class=\\"flex items-center gap-3\\">\\n                  <div class=\\"flex-shrink-0 w-6 h-6 rounded-full flex items-center justify-center\\" style=\\"background: var(--primary-accent);\\">\\n                    <svg class=\\"w-4 h-4 text-white\\" fill=\\"none\\" stroke=\\"currentColor\\" viewBox=\\"0 0 24 24\\">\\n                      <path stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" stroke-width=\\"3\\" d=\\"M5 13l4 4L19 7\\"></path>\\n                    </svg>\\n                  </div>\\n                  <p class=\\"text-base text-themed-secondary\\" style=\\"position: relative;\\">Over 100k happy customers and finished projects.</p>\\n                </div>\\n                \\n                <div class=\\"flex items-center gap-3\\">\\n                  <div class=\\"flex-shrink-0 w-6 h-6 rounded-full flex items-center justify-center\\" style=\\"background: var(--primary-accent);\\">\\n                    <svg class=\\"w-4 h-4 text-white\\" fill=\\"none\\" stroke=\\"currentColor\\" viewBox=\\"0 0 24 24\\">\\n                      <path stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" stroke-width=\\"3\\" d=\\"M5 13l4 4L19 7\\"></path>\\n                    </svg>\\n                  </div>\\n                  <p class=\\"text-base text-themed-secondary\\" style=\\"position: relative;\\">It has 20 branches around the world.</p>\\n                </div>\\n              </div>\\n              \\n              <!-- CTA Button -->\\n              <button class=\\"btn-themed px-8 py-4 text-base font-semibold\\" style=\\"border-radius: var(--button-radius); position: relative;\\">Get Started</button>\\n            </div>\\n            \\n            <!-- Right Column: Image Grid -->\\n            <div class=\\"grid grid-rows-2 gap-4\\">\\n              <!-- Top Row: Two Images -->\\n              <div class=\\"grid grid-cols-2 gap-4\\">\\n                <div class=\\"relative overflow-hidden\\" style=\\"border-radius: var(--card-radius);\\">\\n                  <img src=\\"https://images.unsplash.com/photo-1497366216548-37526070297c?w=600&amp;h=400&amp;fit=crop\\" alt=\\"Team member working on laptop\\" class=\\"w-full h-full object-cover hover:scale-105 transition-transform duration-500\\" style=\\"\\" loading=\\"lazy\\">\\n                </div>\\n                <div class=\\"relative overflow-hidden\\" style=\\"border-radius: var(--card-radius);\\">\\n                  <img src=\\"https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=600&amp;h=400&amp;fit=crop\\" alt=\\"Professional at work\\" class=\\"w-full h-full object-cover hover:scale-105 transition-transform duration-500\\" style=\\"\\" loading=\\"lazy\\">\\n                </div>\\n              </div>\\n              \\n              <!-- Bottom Row: One Large Image -->\\n              <div class=\\"relative overflow-hidden\\" style=\\"border-radius: var(--card-radius);\\">\\n                <img src=\\"https://images.unsplash.com/photo-1556761175-b413da4baf72?w=1200&amp;h=500&amp;fit=crop\\" alt=\\"Team collaboration workspace\\" class=\\"w-full h-full object-cover hover:scale-105 transition-transform duration-500\\" style=\\"\\" loading=\\"lazy\\">\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"143"},{"html":"<section id=\\"fp-theme-testimonials-image\\" class=\\"min-h-screen flex items-center bg-themed-primary has-bg-image section\\" data-section=\\"144\\" data-bg=\\"primary\\" data-original-bg=\\"bg-themed-primary\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20\\">\\n          <!-- Section Header -->\\n          <div class=\\"text-center mb-16\\">\\n            <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold heading-themed mb-4\\" style=\\"font-family: var(--heading-font); position: relative;\\">Success Stories</h2>\\n            <p class=\\"text-xl text-themed-secondary max-w-3xl mx-auto\\" style=\\"position: relative;\\">Hear from our customers about how we''ve transformed their business</p>\\n          </div>\\n\\n          <!-- Testimonial Cards -->\\n          <div class=\\"flex flex-wrap items-center justify-center gap-6\\">\\n            <!-- Testimonial Card 1 -->\\n            <div class=\\"w-96 h-[500px] overflow-hidden relative\\" style=\\"border-radius: var(--card-radius);\\">\\n              <!-- Full Background Image -->\\n              <img src=\\"https://images.unsplash.com/photo-1633332755192-727a05c4013d?q=80&amp;w=600\\" alt=\\"Alex Thompson - Marketing Director\\" class=\\"absolute inset-0 w-full h-full object-cover hover:scale-105 transition-all duration-300\\" style=\\"border-radius: var(--card-radius);\\" loading=\\"lazy\\">\\n              \\n              <!-- Gradient Overlay -->\\n              <div class=\\"absolute inset-0 z-10 pointer-events-none\\" style=\\"background: linear-gradient(to top, rgba(0,0,0,0.9) 0%, rgba(0,0,0,0.7) 50%, rgba(0,0,0,0.3) 80%, transparent 100%); border-radius: var(--card-radius);\\"></div>\\n              \\n              <!-- Card Content -->\\n              <div class=\\"absolute bottom-0 left-0 right-0 z-20 p-6\\">\\n                <p class=\\"text-white text-lg mb-4 font-medium\\" style=\\"position: relative;\\">\\"Radiant made undercutting all of our competitors an absolute breeze.\\"</p>\\n                <div class=\\"w-full h-px bg-white mb-4\\"></div>\\n                <p class=\\"text-white text-lg font-medium\\" style=\\"position: relative;\\">— John Doe</p>\\n                <p class=\\"text-base font-medium\\" style=\\"background: linear-gradient(90deg, rgb(139, 92, 246) 0%, rgb(245, 158, 11) 100%) text; -webkit-text-fill-color: transparent; position: relative;\\">Content Marketing</p>\\n              </div>\\n            </div>\\n\\n            <!-- Testimonial Card 2 -->\\n            <div class=\\"w-96 h-[500px] overflow-hidden relative\\" style=\\"border-radius: var(--card-radius);\\">\\n              <!-- Full Background Image -->\\n              <img src=\\"https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?q=80&amp;w=600\\" alt=\\"Sarah Mitchell - Product Designer\\" class=\\"absolute inset-0 w-full h-full object-cover hover:scale-105 transition-all duration-300\\" style=\\"border-radius: var(--card-radius);\\" loading=\\"lazy\\">\\n              \\n              <!-- Gradient Overlay -->\\n              <div class=\\"absolute inset-0 z-10 pointer-events-none\\" style=\\"background: linear-gradient(to top, rgba(0,0,0,0.9) 0%, rgba(0,0,0,0.7) 50%, rgba(0,0,0,0.3) 80%, transparent 100%); border-radius: var(--card-radius);\\"></div>\\n              \\n              <!-- Card Content -->\\n              <div class=\\"absolute bottom-0 left-0 right-0 z-20 p-6\\">\\n                <p class=\\"text-white text-lg mb-4 font-medium\\" style=\\"position: relative;\\">\\"Radiant made undercutting all of our competitors an absolute breeze.\\"</p>\\n                <div class=\\"w-full h-px bg-white mb-4\\"></div>\\n                <p class=\\"text-white text-lg font-medium\\" style=\\"position: relative;\\">— John Doe</p>\\n                <p class=\\"text-base font-medium\\" style=\\"background: linear-gradient(90deg, rgb(139, 92, 246) 0%, rgb(245, 158, 11) 100%) text; -webkit-text-fill-color: transparent; position: relative;\\">Content Marketing</p>\\n              </div>\\n            </div>\\n\\n            <!-- Testimonial Card 3 -->\\n            <div class=\\"w-96 h-[500px] overflow-hidden relative\\" style=\\"border-radius: var(--card-radius);\\">\\n              <!-- Full Background Image -->\\n              <img src=\\"https://images.unsplash.com/photo-1438761681033-6461ffad8d80?q=80&amp;w=600&amp;h=600&amp;auto=format&amp;fit=crop\\" alt=\\"Emma Rodriguez - CEO\\" class=\\"absolute inset-0 w-full h-full object-cover hover:scale-105 transition-all duration-300\\" style=\\"border-radius: var(--card-radius);\\" loading=\\"lazy\\">\\n              \\n              <!-- Gradient Overlay -->\\n              <div class=\\"absolute inset-0 z-10 pointer-events-none\\" style=\\"background: linear-gradient(to top, rgba(0,0,0,0.9) 0%, rgba(0,0,0,0.7) 50%, rgba(0,0,0,0.3) 80%, transparent 100%); border-radius: var(--card-radius);\\"></div>\\n              \\n              <!-- Card Content -->\\n              <div class=\\"absolute bottom-0 left-0 right-0 z-20 p-6\\">\\n                <p class=\\"text-white text-lg mb-4 font-medium\\" style=\\"position: relative;\\">\\"Radiant made undercutting all of our competitors an absolute breeze.\\"</p>\\n                <div class=\\"w-full h-px bg-white mb-4\\"></div>\\n                <p class=\\"text-white text-lg font-medium\\" style=\\"position: relative;\\">— John Doe</p>\\n                <p class=\\"text-base font-medium\\" style=\\"background: linear-gradient(90deg, rgb(139, 92, 246) 0%, rgb(245, 158, 11) 100%) text; -webkit-text-fill-color: transparent; position: relative;\\">Content Marketing</p>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"144"},{"html":"<section id=\\"fp-theme-logos\\" class=\\"min-h-screen flex items-center has-bg-image section\\" style=\\"background: var(--primary-bg);\\" data-section=\\"145\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20\\">\\n          <!-- Section Header -->\\n          <div class=\\"text-center mb-16\\">\\n            <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold heading-themed mb-4\\" style=\\"font-family: var(--heading-font); position: relative;\\">Trusted companies</h2>\\n            \\n            <!-- Badge -->\\n            <div class=\\"fp-keep-color inline-flex items-center gap-2 px-4 py-2 rounded-full text-themed-secondary text-sm font-medium mb-6\\" style=\\"border: 1px solid var(--border-color); background: var(--secondary-bg);\\">\\n              <svg class=\\"w-4 h-4\\" fill=\\"currentColor\\" viewBox=\\"0 0 20 20\\">\\n                <path fill-rule=\\"evenodd\\" d=\\"M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 18v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.38z\\" clip-rule=\\"evenodd\\"></path>\\n              </svg>\\n              Over 1000+ companies use our components\\n            </div>\\n          </div>\\n\\n          <!-- Logos Grid -->\\n          <div class=\\"grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3 w-max mx-auto\\">\\n            <!-- Logo 1 -->\\n            <div class=\\"flex items-center justify-center h-28 w-52 md:h-32 md:w-64\\" style=\\"background: var(--secondary-bg); border-radius: var(--card-radius);\\">\\n              <img src=\\"public/logos/logo-