TA Button -->\\n              <button class=\\"px-16 py-3.5 font-semibold rounded-lg text-sm transition-all duration-300 hover:scale-105 active:scale-95 uppercase tracking-wider\\" style=\\"background: linear-gradient(135deg, var(--primary-accent) 0%, var(--secondary-accent) 100%); box-shadow: var(--shadow-md); color: rgb(255, 255, 255); position: relative;\\">Get Started</button>\\n            </div>\\n\\n          </div>\\n      </section>","number":"151"},{"html":"<section id=\\"fp-theme-cta-4\\" class=\\"min-h-screen flex items-center justify-center has-bg-image section\\" style=\\"background: var(--secondary-bg);\\" data-section=\\"152\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"fp-keep-color w-full max-w-7xl mx-4 py-16 px-6 md:px-12 rounded-2xl text-center flex flex-col items-center justify-center\\" style=\\"background: var(--primary-bg); box-shadow: var(--shadow-lg); border: 1px solid var(--border-color);\\">\\n            \\n            <!-- Icon -->\\n            <svg width=\\"42\\" height=\\"46\\" viewBox=\\"0 0 42 46\\" fill=\\"none\\" xmlns=\\"http://www.w3.org/2000/svg\\" class=\\"mb-5\\">\\n              <path d=\\"m11.5 6.619 9.5 5.438 9.5-5.438m-19 32.59V28.354L2 22.914m38 0-9.5 5.439V39.21M2.57 12.37 21 22.935l18.43-10.564M21 44V22.914m19 8.368V14.547c0-.734-.196-1.454-.567-2.09a4.2 4.2 0 0 0-1.544-1.53L23.11 2.562a4.25 4.25 0 0 0-4.222 0L4.11 10.928a4.2 4.2 0 0 0-1.544 1.53A4.15 4.15 0 0 0 2 14.546v16.735c0 .733.196 1.454.567 2.089s.903 1.163 1.544 1.53l14.778 8.367a4.25 4.25 0 0 0 4.222 0L37.89 34.9a4.2 4.2 0 0 0 1.544-1.53c.37-.635.566-1.356.567-2.09\\" stroke=\\"currentColor\\" stroke-width=\\"3.5\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" style=\\"color: var(--primary-accent);\\"></path>\\n            </svg>\\n\\n            <!-- Headline -->\\n            <h1 class=\\"text-2xl md:text-3xl lg:text-4xl font-semibold max-w-2xl\\" style=\\"color: var(--primary-te