reliable automation to boost your team''s efficiency.</p>\\n\\n        <!-- Buttons -->\\n        <div class=\\"flex items-center gap-4 mt-8\\">\\n          <button class=\\"rounded-full px-7 h-11 font-semibold transition-all hover:scale-105 active:scale-95\\" style=\\"background: var(--primary-accent); color: white; position: relative;\\">Get started</button>\\n          <button class=\\"flex items-center gap-2 rounded-full px-6 h-11 transition-all hover:opacity-80\\" style=\\"border: 1px solid var(--border-color); background: transparent; color: var(--primary-text); position: relative;\\"><svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"1.5\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" class=\\"lucide lucide-video\\"><path d=\\"m16 13 5.223 3.482a.5.5 0 0 0 .777-.416V7.87a.5.5 0 0 0-.752-.432L16 10.5\\"></path><rect x=\\"2\\" y=\\"6\\" width=\\"14\\" height=\\"12\\" rx=\\"2\\"></rect></svg>Watch demo</button>\\n        </div>\\n\\n        <!-- Feature Checks -->\\n        <div class=\\"flex flex-wrap justify-center items-center gap-4 md:gap-14 mt-12\\">\\n          <p class=\\"flex items-center gap-2\\" style=\\"position: relative;\\"><svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" class=\\"lucide lucide-check size-5\\" style=\\"color: var(--primary-accent);\\"><path d=\\"M20 6 9 17l-5-5\\"></path></svg><span style=\\"color: var(--secondary-text);\\">No credit card</span></p>\\n          <p class=\\"flex items-center gap-2\\" style=\\"position: relative;\\"><svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" class=\\"l