\"\\" playsinline=\\"\\" onloadedmetadata=\\"this.muted = true\\">\\n                  <source src=\\"https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4\\" type=\\"video/mp4\\">\\n                </video>\\n              </div>\\n            </div>\\n          </div>\\n\\n          <!-- Statistics Grid -->\\n          <div class=\\"grid grid-cols-2 lg:grid-cols-4 gap-8\\">\\n            <div class=\\"text-center\\">\\n              <h3 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-3\\" style=\\"font-family: var(--heading-font); color: var(--primary-accent); position: relative;\\">25+</h3>\\n              <p class=\\"text-lg text-themed-secondary\\" style=\\"position: relative;\\">Years of Experience</p>\\n            </div>\\n            <div class=\\"text-center\\">\\n              <h3 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-3\\" style=\\"font-family: var(--heading-font); color: var(--primary-accent); position: relative;\\">90+</h3>\\n              <p class=\\"text-lg text-themed-secondary\\" style=\\"position: relative;\\">Team Members</p>\\n            </div>\\n            <div class=\\"text-center\\">\\n              <h3 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-3\\" style=\\"font-family: var(--heading-font); color: var(--primary-accent); position: relative;\\">64+</h3>\\n              <p class=\\"text-lg text-themed-secondary\\" style=\\"position: relative;\\">Successful Projects</p>\\n            </div>\\n            <div class=\\"text-center\\">\\n              <h3 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-3\\" style=\\"font-family: var(--heading-font); color: var(--primary-accent); position: relative;\\">60+</h3>\\n              <p class=\\"text-lg text-themed-secondary\\" style=\\"position: relative;\\">Happy Clients</p>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"160"},{"html":"<section id=\\"fp-theme-achievement-story\\" class=\\"min-h-screen flex items-center py-20 has-bg-image section\\" style=\\"background: var(--primary-bg); --spacing-unit: 0.8rem;\\" data-section=\\"161\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full\\">\\n          <div class=\\"grid lg:grid-cols-2 gap-16 items-center\\">\\n            <!-- Left Content -->\\n            <div>\\n              <p class=\\"text-sm uppercase tracking-wider mb-4 text-themed-secondary\\" style=\\"position: relative;\\">About Us</p>\\n              <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-6 heading-themed\\" style=\\"font-family: var(--heading-font); color: var(--primary-accent); position: relative;\\">The Tale of Our Achievement Story</h2>\\n              <p class=\\"text-lg mb-12 text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Our achievement story is a testament to teamwork and perseverance. Together, we''ve overcome challenges, and created a narrative of progress and success.</p>\\n\\n              <!-- Stats Grid -->\\n              <div class=\\"fp-keep-color grid grid-cols-2 gap-6 mb-8\\">\\n                <div class=\\"card-themed p-6 transition-all duration-300 hover:scale-105\\">\\n                  <h3 class=\\"text-2xl md:text-3xl font-bold mb-2\\" style=\\"font-family: var(--heading-font); color: var(--primary-accent); position: relative;\\">33+ Years</h3>\\n                  <p class=\\"text-themed-secondary text-sm\\" style=\\"position: relative;\\">Influencing Digital Landscapes Together</p>\\n                </div>\\n\\n                <div class=\\"card-themed p-6 transition-all duration-300 hover:scale-105\\">\\n                  <h3 class=\\"text-2xl md:text-3xl font-bold mb-2\\" style=\\"font-family: var(--heading-font); color: var(--primary-accent); position: relative;\\">125+ Projects</h3>\\n                  <p class=\\"text-themed-secondary text-sm\\" style=\\"position: relative;\\">Excellence Achieved Through Success</p>\\n                </div>\\n\\n                <div class=\\"card-themed p-6 transition-all duration-300 hover:scale-105\\">\\n                  <h3 class=\\"text-2xl md:text-3xl font-bold mb-2\\" style=\\"font-family: var(--heading-font); color: var(--primary-accent); position: relative;\\">26+ Awards</h3>\\n                  <p class=\\"text-themed-secondary text-sm\\" style=\\"position: relative;\\">Our Dedication to Innovation Wins Understanding</p>\\n                </div>\\n\\n                <div class=\\"card-themed p-6 transition-all duration-300 hover:scale-105\\">\\n                  <h3 class=\\"text-2xl md:text-3xl font-bold mb-2\\" style=\\"font-family: var(--heading-font); color: var(--primary-accent); position: relative;\\">99% Happy Clients</h3>\\n                  <p class=\\"text-themed-secondary text-sm\\" style=\\"position: relative;\\">Mirrors our Focus on Client Satisfaction</p>\\n                </div>\\n              </div>\\n\\n              <!-- Read More Button -->\\n              <a href=\\"#\\" class=\\"btn-themed inline-flex items-center gap-2\\" style=\\"position: relative;\\">Read More\\n<svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"20\\" height=\\"20\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\">\\n                  <polyline points=\\"9 18 15 12 9 6\\"></polyline>\\n                </svg></a>\\n            </div>\\n\\n            <!-- Right Image -->\\n            <div>\\n              <div class=\\"relative overflow-hidden\\" style=\\"border-radius: var(--card-radius); box-shadow: var(--shadow-xl);\\">\\n                <img src=\\"https://images.unsplash.com/photo-1522071820081-009f0129c71c?w=800&amp;h=900&amp;fit=crop\\" alt=\\"Team collaboration in modern office\\" class=\\"w-full h-auto object-cover\\" style=\\"\\" loading=\\"lazy\\">\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"161"},{"html":"<section id=\\"fp-theme-step-cards\\" class=\\"min-h-screen flex items-center py-20 has-bg-image section\\" style=\\"background: var(--primary-bg);\\" data-section=\\"167\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full\\">\\n          <!-- Header -->\\n          <div class=\\"text-center mb-16\\">\\n            <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-4 heading-themed\\" style=\\"font-family: var(--heading-font); color: var(--primary-accent); position: relative;\\">How It Works</h2>\\n            <p class=\\"text-xl text-themed-secondary max-w-2xl mx-auto\\" style=\\"position: relative;\\">Four Simple Steps to Transform Your Vision Into Reality</p>\\n          </div>\\n\\n          <!-- Steps Grid -->\\n          <div class=\\"fp-keep-color grid md:grid-cols-2 gap-8\\">\\n            <!-- Step 1 -->\\n            <div class=\\"card-themed overflow-hidden transition-all duration-300 hover:scale-[1.02] hover:-translate-y-1\\" style=\\"border-radius: var(--card-radius); box-shadow: var(--shadow-lg);\\">\\n              <div class=\\"!p-4 flex items-center h-full\\">\\n                <div class=\\"flex-1 pr-4\\">\\n                  <span class=\\"text-lg font-semibold\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">Step 1</span>\\n                  <h3 class=\\"text-xl md:text-2xl font-bold heading-themed mt-2 mb-4\\" style=\\"font-family: var(--heading-font); position: relative;\\">Define Your Vision</h3>\\n                  <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Share your goals and aspirations with us. We''ll understand your needs and create a foundation for success.</p>\\n                </div>\\n                <div class=\\"flex-shrink-0\\">\\n                  <img src=\\"public/images/business-team.jpg\\" alt=\\"Team collaboration\\" class=\\"w-40 h-40 object-cover rounded-lg\\" style=\\"border-radius: var(--card-radius);\\" loading=\\"lazy\\">\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- Step 2 -->\\n            <div class=\\"card-themed overflow-hidden transition-all duration-300 hover:scale-[1.02] hover:-translate-y-1\\" style=\\"border-radius: var(--card-radius); box-shadow: var(--shadow-lg);\\">\\n              <div class=\\"!p-4 flex items-center h-full\\">\\n                <div class=\\"flex-1 pr-4\\">\\n                  <span class=\\"text-lg font-semibold\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">Step 2</span>\\n                  <h3 class=\\"text-xl md:text-2xl font-bold heading-themed mt-2 mb-4\\" style=\\"font-family: var(--heading-font); position: relative;\\">Strategic Planning</h3>\\n                  <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Our expert team develops a comprehensive roadmap tailored to your objectives and vision.</p>\\n                </div>\\n                <div class=\\"flex-shrink-0\\">\\n                  <img src=\\"public/images/workspace.jpg\\" alt=\\"Strategic workspace\\" class=\\"w-40 h-40 object-cover rounded-lg\\" style=\\"border-radius: var(--card-radius);\\" loading=\\"lazy\\">\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- Step 3 -->\\n            <div class=\\"card-themed overflow-hidden transition-all duration-300 hover:scale-[1.02] hover:-translate-y-1\\" style=\\"border-radius: var(--card-radius); box-shadow: var(--shadow-lg);\\">\\n              <div class=\\"!p-4 flex items-center h-full\\">\\n                <div class=\\"flex-1 pr-4\\">\\n                  <span class=\\"text-lg font-semibold\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">Step 3</span>\\n                  <h3 class=\\"text-xl md:text-2xl font-bold heading-themed mt-2 mb-4\\" style=\\"font-family: var(--heading-font); position: relative;\\">Collaborative Execution</h3>\\n                  <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Work alongside our dedicated team as we bring your project to life with transparency and open communication.</p>\\n                </div>\\n                <div class=\\"flex-shrink-0\\">\\n                  <img src=\\"public/images/person-1.jpg\\" alt=\\"Team collaboration\\" class=\\"w-40 h-40 object-cover rounded-lg\\" style=\\"border-radius: var(--card-radius);\\" loading=\\"lazy\\">\\n                </div>\\n              </div>\\n            </div>\\n\\n            <!-- Step 4 -->\\n            <div class=\\"card-themed overflow-hidden transition-all duration-300 hover:scale-[1.02] hover:-translate-y-1\\" style=\\"border-radius: var(--card-radius); box-shadow: var(--shadow-lg);\\">\\n              <div class=\\"!p-4 flex items-center h-full\\">\\n                <div class=\\"flex-1 pr-4\\">\\n                  <span class=\\"text-lg font-semibold\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">Step 4</span>\\n                  <h3 class=\\"text-xl md:text-2xl font-bold heading-themed mt-2 mb-4\\" style=\\"font-family: var(--heading-font); position: relative;\\">Launch &amp; Grow</h3>\\n                  <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Celebrate your success as we deliver exceptional results and support your growth with ongoing optimization.</p>\\n                </div>\\n                <div class=\\"flex-shrink-0\\">\\n                  <img src=\\"public/images/phone-screen.jpg\\" alt=\\"Launch success\\" class=\\"w-40 h-40 object-cover rounded-lg\\" style=\\"border-radius: var(--card-radius);\\" loading=\\"lazy\\">\\n                </div>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n      </section>","number":"167"},{"html":"<section id=\\"fp-theme-steps-slider\\" class=\\"min-h-screen flex items-center py-20 has-bg-image section\\" style=\\"background: var(--secondary-bg);\\" data-section=\\"168\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full\\">\\n          <!-- Header -->\\n          <div class=\\"text-center mb-16\\">\\n            <p class=\\"text-lg font-semibold mb-3 text-themed-secondary\\" style=\\"font-family: var(--heading-font); position: relative;\\">Getting Started</p>\\n            <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold heading-themed\\" style=\\"font-family: var(--heading-font); color: var(--primary-accent); position: relative;\\">Steps to Get Started</h2>\\n          </div>\\n\\n          <!-- Slider Container -->\\n          <div class=\\"grid md:grid-cols-2 gap-12 items-center\\">\\n            <!-- Static Image -->\\n            <div class=\\"order-2 md:order-1\\">\\n              <div class=\\"card-themed overflow-hidden\\" style=\\"border-radius: var(--card-radius); box-shadow: var(--shadow-lg);\\">\\n                <img src=\\"public/images/business-team.jpg\\" alt=\\"Steps illustration\\" class=\\"w-full h-96 object-cover\\" style=\\"\\" loading=\\"lazy\\">\\n              </div>\\n            </div>\\n            \\n            <!-- Sliding Text Content -->\\n            <div class=\\"order-1 md:order-2\\">\\n              <div class=\\"relative overflow-hidden\\">\\n                <div class=\\"steps-slider-track flex transition-transform duration-500 ease-in-out\\" style=\\"transform: translateX(0%);\\">\\n                  \\n                  <!-- Slide 1 -->\\n                  <div class=\\"steps-slider-slide flex-shrink-0 w-full\\">\\n                    <p class=\\"text-lg font-semibold mb-3\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">1st Step</p>\\n                    <h3 class=\\"text-3xl md:text-4xl font-bold heading-themed mb-6\\" style=\\"font-family: var(--heading-font); position: relative;\\">Create Your Account</h3>\\n                    <p class=\\"text-lg text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Begin your journey by signing up for a free account. Provide your basic information and set up your profile to unlock all features. Our streamlined registration process takes less than two minutes, allowing you to start building immediately.</p>\\n                  </div>\\n\\n                  <!-- Slide 2 -->\\n                  <div class=\\"steps-slider-slide flex-shrink-0 w-full\\">\\n                    <p class=\\"text-lg font-semibold mb-3\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">2nd Step</p>\\n                    <h3 class=\\"text-3xl md:text-4xl font-bold heading-themed mb-6\\" style=\\"font-family: var(--heading-font); position: relative;\\">Gather Required Documents</h3>\\n                    <p class=\\"text-lg text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Collect necessary documents such as identification (passport or driver''s license), proof of address (utility bill or lease agreement), and Social Security Number (or equivalent for your country). Having these ready will ensure a smooth verification process.</p>\\n                  </div>\\n\\n                  <!-- Slide 3 -->\\n                  <div class=\\"steps-slider-slide flex-shrink-0 w-full\\">\\n                    <p class=\\"text-lg font-semibold mb-3\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">3rd Step</p>\\n                    <h3 class=\\"text-3xl md:text-4xl font-bold heading-themed mb-6\\" style=\\"font-family: var(--heading-font); position: relative;\\">Complete Verification</h3>\\n                    <p class=\\"text-lg text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Upload your documents through our secure portal and complete the verification process. Our advanced system will review your information promptly, typically within 24 hours. You''ll receive instant notifications about your verification status throughout the process.</p>\\n                  </div>\\n\\n                  <!-- Slide 4 -->\\n                  <div class=\\"steps-slider-slide flex-shrink-0 w-full\\">\\n                    <p class=\\"text-lg font-semibold mb-3\\" style=\\"color: var(--primary-accent); font-family: var(--heading-font); position: relative;\\">4th Step</p>\\n                    <h3 class=\\"text-3xl md:text-4xl font-bold heading-themed mb-6\\" style=\\"font-family: var(--heading-font); position: relative;\\">Start Using the Platform</h3>\\n                    <p class=\\"text-lg text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Once verified, you''re ready to explore all features and tools at your disposal. Access your personalized dashboard, customize your settings, and begin leveraging our powerful platform to achieve your goals. Our support team is always here to help you maximize your experience.</p>\\n                  </div>\\n\\n                </div>\\n              </div>\\n            </div>\\n          </div>\\n\\n          <!-- Navigation Dots -->\\n          <div class=\\"flex justify-center gap-4 mt-12\\">\\n            <button class=\\"steps-slider-nav w-12 h-12 rounded-full flex items-center justify-center font-semibold transition-all duration-300\\" data-slide=\\"0\\" style=\\"background: var(--primary-accent); color: white; font-family: var(--heading-font); border: none; transform: scale(1.1); position: relative;\\">1</button>\\n            <button class=\\"steps-slider-nav w-12 h-12 rounded-full flex items-center justify-center font-semibold transition-all duration-300\\" data-slide=\\"1\\" style=\\"background: var(--card-bg); color: var(--primary-accent); font-family: var(--heading-font); border: 2px solid var(--border-color); transform: scale(1); position: relative;\\">2</button>\\n            <button class=\\"steps-slider-nav w-12 h-12 rounded-full flex items-center justify-center font-semibold transition-all duration-300\\" data-slide=\\"2\\" style=\\"background: var(--card-bg); color: var(--primary-accent); font-family: var(--heading-font); border: 2px solid var(--border-color); transform: scale(1); position: relative;\\">3</button>\\n            <button class=\\"steps-slider-nav w-12 h-12 rounded-full flex items-center justify-center font-semibold transition-all duration-300\\" data-slide=\\"3\\" style=\\"background: var(--card-bg); color: var(--primary-accent); font-family: var(--heading-font); border: 2px solid var(--border-color); transform: scale(1); position: relative;\\">4</button>\\n          </div>\\n        </div>\\n      </section>","number":"168"},{"html":"<section id=\\"fp-theme-testimonials-cards\\" class=\\"min-h-screen flex items-center py-20 has-bg-image section\\" style=\\"background: var(--primary-bg);\\" data-section=\\"169\\" data-bg=\\"default\\" data-original-bg=\\"\\">\\n        <div class=\\"fp-bg\\"></div>\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full\\">\\n          <!-- Header -->\\n          <div class=\\"text-center mb-16\\">\\n            <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-4 heading-themed\\" style=\\"font-family: var(--heading-font); position: relative;\\">Loved by Professionals</h2>\\n            <p class=\\"text-xl text-themed-secondary max-w-3xl mx-auto\\" style=\\"position: relative;\\">Don''t just take our word for it. Here''s what our users are saying about their experience.</p>\\n          </div>\\n\\n          <!-- Testimonials Grid -->\\n          <div class=\\"flex flex-wrap justify-center gap-8\\">\\n            \\n 