=\\"Email address\\" class=\\"w-full px-6 py-4 text-lg\\" style=\\"border-radius: var(--card-radius); background-color: var(--primary-bg); color: var(--primary-text); border: 1px solid var(--border-color);\\">\\n            <\\/div>\\n            <div>\\n              <textarea placeholder=\\"Message\\" rows=\\"6\\" class=\\"w-full px-6 py-4 text-lg resize-none\\" style=\\"border-radius: var(--card-radius); background-color: var(--primary-bg); color: var(--primary-text); border: 1px solid var(--border-color);\\"><\\/textarea>\\n            <\\/div>\\n            <a href=\\"\\" type=\\"submit\\" class=\\"justify-center flex w-full px-8 py-4 text-lg font-semibold text-white\\" style=\\"border-radius: var(--card-radius); background: linear-gradient(135deg, rgb(255, 64, 129), rgb(255, 107, 157)); position: relative;\\">Send message<\\/a><input type=\\"hidden\\" name=\\"tinymce-skbqto8zg\\">\\n          <\\/form>\\n        <\\/div>\\n      <\\/section>"},{"number":"6","html":"<section id=\\"fp-theme-customer-testimonial\\" class=\\"min-h-screen flex items-center bg-themed-secondary section\\" data-section=\\"6\\" data-bg=\\"secondary\\" data-original-bg=\\"bg-themed-secondary\\" style=\\"\\">\\n        <div class=\\"max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-20\\">\\n          <div class=\\"text-center mb-16\\">\\n            <h2 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold heading-themed mb-12\\">What our customers say<\\/h2>\\n          <\\/div>\\n          <div class=\\"max-w-4xl mx-auto\\">\\n            <div class=\\"text-center mb-12\\">\\n              <p class=\\"text-xl md:text-2xl text-themed-primary leading-relaxed mb-8\\">\\"You made it so simple. My new site is so much faster and easier to work with than my old site. I just choose the page, make the change and click save. No need to think twice before making it\\"<\\/p>\\n            <\\/div>\\n            <div class=\\"flex flex-col items-center\\">\\n              <div class=\\"mb-6\\">\\n                <h4 class=\\"text-xl font-bold heading-themed mb-2\\">Jenny Wilson<\\/h4>\\n                <p class=\\"text-themed-secondary\\">Co-founder, Appson<\\/p>\\n              <\\/div>\\n              <div class=\\"flex space-x-4\\">\\n                <div class=\\"w-12 h-12 rounded-full overflow-hidden border-2 border-themed-accent\\">\\n                  <img src=\\"https:\\/\\/images.unsplash.com\\/photo-1438761681033-6461ffad8d80?ixlib=rb-4.0.3&amp;auto=format&amp;fit=crop&amp;w=60&amp;h=60&amp;q=80\\" alt=\\"Customer\\" class=\\"w-full h-full object-cover\\" style=\\"\\">\\n                <\\/div>\\n                <div class=\\"w-12 h-12 rounded-full overflow-hidden border border-themed\\">\\n                  <img src=\\"https:\\/\\/images.unsplash.com\\/photo-1472099645785-5658abf4ff4e?w=60&amp;h=60&amp;fit=crop&amp;crop=face\\" alt=\\"Customer\\" class=\\"w-full h-full object-cover\\" style=\\"\\">\\n                <\\/div>\\n                <div class=\\"w-12 h-12 rounded-full overflow-hidden border border-themed\\">\\n                  <img src=\\"https:\\/\\/images.unsplash.com\\/photo-1438761681033-6461ffad8d80?w=60&amp;h=60&amp;fit=crop&amp;crop=face\\" alt=\\"Customer\\" class=\\"w-full h-full object-cover\\" style=\\"\\">\\n                <\\/div>\\n              <\\/div>\\n            <\\/div>\\n          <\\/div>\\n        <\\/div>\\n      \\n        \\n    \\n        \\n    <\\/section>"}],"theme":"theme-dark-modern","fullpageEnabled":false,"animationsEnabled":false,"selectedSections":[50,6],"timestamp":1764103720673}', null, 'false', 'false', 'ce639ddb-346b-43cf-ba7e-5ed597c840ea', '2025-11-25 20:48:41+00', '2025-11-20 18:11:52+00', '2025-11-25 20:48:41.534352+00'), ('4c1a48e5-2d1b-4f78-94d8-363d7a813c2f', '3', 'Test', '{"sections":[{"number":"0","html":"<section id=\\"fp-theme-discussion\\" class=\\"min-h-screen flex items-center gradient-themed-2 section\\" data-section=\\"0\\" data-bg=\\"gradient-2\\" data-original-bg=\\"gradient-themed-2\\">\\n        <div class=\\"max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-20 text-center\\">\\n          <h1 class=\\"text-4xl md:text-5xl lg:text-6xl font-bold mb-8 text-white\\" style=\\"color: white !important; position: relative;\\">Test Alvaro<\\/h1>\\n          <p class=\\"text-lg md:text-xl mb-16 text-white text-opacity-90 max-w-4xl mx-auto leading-relaxed\\" style=\\"position: relative;\\">There is something artificial when everyone is agreeing with each other. It''s useful to include people who don''t agree, and see their viewpoint or force yourself to explain things better.<\\/p>\\n          <div class=\\"max-w-3xl mx-auto\\">\\n            <div class=\\"relative overflow-hidden rounded-2xl shadow-2xl\\">\\n              <img src=\\"https:\\/\\/images.unsplash.com\\/photo-1605810230434-7631ac76ec81?w=800&amp;h=500&amp;fit=crop\\" alt=\\"Group of people in discussion around video displays\\" class=\\"w-full h-auto object-cover\\" style=\\"\\">\\n            <\\/div>\\n          <\\/div>\\n        <\\/div>\\n      <\\/section>"},{"number":"1","html":"<section id=\\"fp-theme-features-accordion\\" class=\\"min-h-screen flex items-center section\\" data-section=\\"1\\" data-bg=\\"primary\\" data-original-bg=\\"bg-themed-primary\\" style=\\"background-color: var(--primary-bg);\\">\\n        <div class=\\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full py-20\\">\\n          <div class=\\"grid lg:grid-cols-2 gap-16 items-start\\">\\n            <!-- Left Side - Accordion -->\\n            <div>\\n              <h2 class=\\"text-4xl md:text-5xl font-bold heading-themed mb-12\\" style=\\"position: relative;\\">Significant others<\\/h2>\\n              \\n              <div class=\\"space-y-4\\" id=\\"features-accordion\\">\\n                <!-- Feature 1 - Expanded by default -->\\n                <div class=\\"bg-themed-secondary rounded-2xl overflow-hidden feature-item\\" style=\\"border-radius: var(--card-radius); box-shadow: var(--shadow-sm);\\">\\n                  <button class=\\"w-full p-6 flex items-center justify-between text-left feature-toggle\\" style=\\"position: relative;\\"><span class=\\"text-xl font-bold heading-themed\\">iPhone and Mac<\\/span><svg xmlns=\\"http:\\/\\/www.w3.org\\/2000\\/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-right\\" class=\\"lucide lucide-chevron-right w-6 h-6 text-themed-primary transition-transform\\" style=\\"transform: rotate(90deg);\\"><path d=\\"m9 18 6-6-6-6\\"><\\/path><\\/svg><\\/button>\\n                  <div class=\\"feature-content px-6 pb-6\\">\\n                    <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Seamlessly integrate your iPhone with your Mac for a unified experience. Share files instantly, take calls on your Mac, and use your iPhone as a webcam. Universal Clipboard lets you copy on one device and paste on another.<\\/p>\\n                  <\\/div>\\n                <\\/div>\\n\\n                <!-- Feature 2 -->\\n                <div class=\\"bg-themed-secondary rounded-2xl overflow-hidden feature-item\\" style=\\"border-radius: var(--card-radius); box-shadow: var(--shadow-sm);\\">\\n                  <button class=\\"w-full p-6 flex items-center justify-between text-left feature-toggle\\" style=\\"position: relative;\\"><span class=\\"text-xl font-bold heading-themed\\">iPhone and Apple Watch<\\/span><svg xmlns=\\"http:\\/\\/www.w3.org\\/2000\\/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-right\\" class=\\"lucide lucide-chevron-right w-6 h-6 text-themed-primary transition-transform\\" style=\\"transform: rotate(0deg);\\"><path d=\\"m9 18 6-6-6-6\\"><\\/path><\\/svg><\\/button>\\n                  <div class=\\"feature-content px-6 pb-6 hidden\\">\\n                    <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Misplaced your iPhone? The latest Apple Watch models can show you its approximate distance and direction. To set up a group photo on your iPhone, join the group and use Apple Watch as a viewfinder to snap the shot. And when you take a call on your Apple Watch, just tap your iPhone to continue the conversation there.<\\/p>\\n                  <\\/div>\\n                <\\/div>\\n\\n                <!-- Feature 3 -->\\n                <div class=\\"bg-themed-secondary rounded-2xl overflow-hidden feature-item\\" style=\\"border-radius: var(--card-radius); box-shadow: var(--shadow-sm);\\">\\n                  <button class=\\"w-full p-6 flex items-center justify-between text-left feature-toggle\\" style=\\"position: relative;\\"><span class=\\"text-xl font-bold heading-themed\\">iPhone and AirPods<\\/span><svg xmlns=\\"http:\\/\\/www.w3.org\\/2000\\/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-right\\" class=\\"lucide lucide-chevron-right w-6 h-6 text-themed-primary transition-transform\\" style=\\"transform: rotate(0deg);\\"><path d=\\"m9 18 6-6-6-6\\"><\\/path><\\/svg><\\/button>\\n                  <div class=\\"feature-content px-6 pb-6 hidden\\">\\n                    <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Experience crystal-clear audio with seamless switching between devices. Spatial audio creates an immersive listening experience, while active noise cancellation blocks out distractions. Conversation Boost makes voices clearer in crowded environments.<\\/p>\\n                  <\\/div>\\n                <\\/div>\\n\\n                <!-- Feature 4 -->\\n                <div class=\\"bg-themed-secondary rounded-2xl overflow-hidden feature-item\\" style=\\"border-radius: var(--card-radius); box-shadow: var(--shadow-sm);\\">\\n                  <button class=\\"w-full p-6 flex items-center justify-between text-left feature-toggle\\" style=\\"position: relative;\\"><span class=\\"text-xl font-bold heading-themed\\">iPhone and iPad<\\/span><svg xmlns=\\"http:\\/\\/www.w3.org\\/2000\\/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" data-lucide=\\"chevron-right\\" class=\\"lucide lucide-chevron-right w-6 h-6 text-themed-primary transition-transform\\" style=\\"transform: rotate(0deg);\\"><path d=\\"m9 18 6-6-6-6\\"><\\/path><\\/svg><\\/button>\\n                  <div class=\\"feature-content px-6 pb-6 hidden\\">\\n                    <p class=\\"text-themed-secondary leading-relaxed\\" style=\\"position: relative;\\">Start a project on your iPhone and finish it on your iPad with Handoff. Use your iPad as a second display with Sidecar. Draw with Apple Pencil and insert sketches directly into documents on your iPhone.<\\/p>\\n                  <\\/div>\\n                <\\/div>\\n              <\\/div>\\n            <\\/div>\\n\\n            <!-- Right Side - Visual -->\\n            <div class=\\"lg:sticky lg:top-20\\">\\n              <div class=\\"relative rounded-3xl overflow-hidden\\" style=\\"border-radius: var(--card-radius); box-shadow: var(--shadow-lg);\\">\\n                <img src=\\"https:\\/\\/images.unsplash.com\\/photo-1691256676376-357c3aa66c89?ixlib=rb-4.1.0&amp;ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&amp;auto=format&amp;fit=crop&amp;q=80&amp;w=1760\\" alt=\\"Device ecosystem\\" class=\\"w-full h-auto object-cover\\" style=\\"\\">\\n              <\\/div>\\n            <\\/div>\\n          <\\/div>\\n        <\\/div>\\n      <\\/section>"},{"number":"2","html":"<section id=\\"fp-theme-form-split\\" class=\\"min-h-screen f